pub enum FunctionValuePropertyOperationOutcome {
    Returned,
    Threw,
    Failed,
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub enum FunctionValueCallCompletion {
    TailCallResult(FunctionValueCallTailCompletion),
    PropertyOperation(FunctionValuePropertyOperationCompletion),
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct FunctionValuePropertyOperationContext {
    resume: FunctionValuePropertyOperationResume,
    transform: FunctionValueReturnTransform,
    observation: Option<FunctionValuePropertyObservation>,
}

impl FunctionValuePropertyOperationContext {
    fn with_observation(self, observation: FunctionValuePropertyObservation) -> Self {
        Self {
            observation: Some(observation),
            ..self
        }
    }

    fn completion(
        self,
        observation: FunctionValuePropertyObservation,
    ) -> FunctionValueCallCompletion {
        let observation = self.observation.unwrap_or(observation);
        FunctionValueCallCompletion::PropertyOperation(FunctionValuePropertyOperationCompletion {
            resume: self.resume,
            transform: self.transform,
            observation,
        })
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct FunctionValuePropertyStoreObservationContext {
    site: CorePropertyStoreSite,
    before: CorePropertyStoreSnapshot,
    barrier_start: usize,
}

impl FunctionValuePropertyStoreObservationContext {
    fn observation(
        self,
        object: RuntimeValue,
        key: CorePropertyKey,
        value: RuntimeValue,
        returned_outcome: PropertyStoreObservationOutcome,
    ) -> FunctionValuePropertyObservation {
        FunctionValuePropertyObservation::property_store(
            self.site,
            object,
            key,
            value,
            self.before,
            self.barrier_start,
            returned_outcome,
        )
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct FunctionValuePropertyCallCompletion {
    context: Option<FunctionValuePropertyOperationContext>,
    observation: FunctionValuePropertyObservation,
}

impl FunctionValuePropertyCallCompletion {
    fn none(context: Option<FunctionValuePropertyOperationContext>) -> Self {
        Self {
            context,
            observation: FunctionValuePropertyObservation::none(),
        }
    }

    fn with_observation(
        context: Option<FunctionValuePropertyOperationContext>,
        observation: FunctionValuePropertyObservation,
    ) -> Self {
        Self {
            context,
            observation,
        }
    }

    fn into_completion(self) -> Option<FunctionValueCallCompletion> {
        let Self {
            context,
            observation,
        } = self;
        context.map(|context| context.completion(observation))
    }

    fn into_context(self) -> Option<FunctionValuePropertyOperationContext> {
        let Self {
            context,
            observation,
        } = self;
        context.map(|context| context.with_observation(observation))
    }
}

#[derive(Clone, Debug)]
pub struct FunctionValueCallRequest {
    pub(crate) completion: FunctionValueCallCompletion,
    pub(crate) callee_value: RuntimeValue,
    pub(crate) callee_object: Option<ObjectId>,
    pub(crate) target_code_block_id: CodeBlockId,
    // C++ JSC divergence (one shared instance): see `OrdinaryBytecodeCallRequest`.
    pub(crate) target_code_block: Rc<CodeBlock>,
    pub(crate) argument_values: Vec<RuntimeValue>,
}

impl PartialEq for FunctionValueCallRequest {
    fn eq(&self, other: &Self) -> bool {
        self.completion == other.completion
            && self.callee_value == other.callee_value
            && self.callee_object == other.callee_object
            && self.target_code_block_id == other.target_code_block_id
            && code_blocks_request_eq(&self.target_code_block, &other.target_code_block)
            && self.argument_values == other.argument_values
    }
}

impl Eq for FunctionValueCallRequest {}

// C++ JSC divergence (instance identity): C++ compares call targets by
// `CodeBlock*` identity. When two requests share the one stable `Rc<CodeBlock>`
// (the runtime path), `Rc::ptr_eq` is an O(1) identity match — strictly more
// faithful than the old structural compare. The structural fallback (used by
// test-constructed, non-shared blocks) preserves the previous equality so tests
// that build two distinct-but-equal blocks still compare equal.
fn code_blocks_request_eq(left: &Rc<CodeBlock>, right: &Rc<CodeBlock>) -> bool {
    if Rc::ptr_eq(left, right) {
        return true;
    }
    std::sync::Arc::ptr_eq(left.shared_unlinked(), right.shared_unlinked())
        && left.link_context() == right.link_context()
        && left.entrypoints() == right.entrypoints()
        && left.lifecycle() == right.lifecycle()
}

/// Deferred INDIRECT (global) eval request.
///
/// C++ JSC globalFuncEval (runtime/JSGlobalObjectFunctions.cpp:450) compiles
/// the program source as an IndirectEvalExecutable and runs it via
/// `vm.interpreter.executeEval(eval, globalObject->globalThis(),
/// globalObject->globalScope())` (:517-522). In Rust the native `eval` arm
/// cannot compile inline: the compile pipeline lives on the Vm and mutates
/// `&mut Vm` state (executable/code-block registries) that is not reachable
/// while the per-instruction dispatch holds its `DispatchState` borrows. So the
/// native arm extracts the source string and the call-site resume context, drops
/// all borrows, and returns this request; the Vm handler
/// (`execute_eval_request_in_current_region`) owns compile+link+run and writes
/// the completion value back into the call destination via the same
/// `FunctionValueCallCompletion` resume path used by deferred function-value
/// calls.
#[derive(Clone, Debug, Eq, PartialEq)]
pub struct EvalRequest {
    /// Program source text (the string `eval` was given). Mirrors C++
    /// `programSource` (JSGlobalObjectFunctions.cpp:456).
    pub(crate) source: String,
    /// Call-site resume context: caller frame/window, owner code block, call +
    /// resume bytecode indices, and the destination register the eval result is
    /// written to. Reuses the deferred function-value-call completion machinery.
    pub(crate) completion: FunctionValueCallCompletion,
    /// Global object value, used as `this` for the eval CodeBlock's single
    /// parameter (`globalObject->globalThis()`, Interpreter.cpp:1488).
    pub(crate) global_this: RuntimeValue,
}

/// Deferred `Function(...)` (dynamic function compilation) request.
///
/// C++ JSC callFunctionConstructor -> constructFunction
/// (runtime/FunctionConstructor.cpp:48-56, :320-323) stringifies the arguments
/// into a function-source program and compiles a `FunctionExecutable` in the
/// global realm via `FunctionExecutable::fromGlobalCode`, returning a `JSFunction`
/// WITHOUT running its body. This is a sibling of `EvalRequest`: like indirect
/// eval, the native arm cannot compile inline (the compile pipeline mutates
/// `&mut Vm` registries unreachable while per-instruction `DispatchState` borrows
/// are held), so it extracts the ASSEMBLED source plus the call-site resume
/// context, drops all borrows, and returns this request. The Vm handler
/// (`execute_compile_function_request_in_current_region`) owns compile+link and
/// writes the resulting function object back through the same
/// `FunctionValueCallCompletion` resume path used by deferred function-value
/// calls. It is a DISTINCT type from `EvalRequest` because `constructFunction`
/// and `globalFuncEval` are distinct C++ runtime entries with distinct source
/// assembly, even though the Rust port currently reuses the eval compile core.
#[derive(Clone, Debug, Eq, PartialEq)]
pub struct CompileFunctionRequest {
    /// Already-ASSEMBLED program source. The native arm builds this faithfully to
    /// `stringifyFunction` (FunctionConstructor.cpp:217-302), then wraps it in
    /// parentheses so the Rust eval compile core (`build_and_run_eval_code_block`)
    /// evaluates a function EXPRESSION and yields the function object as its
    /// completion value (see `assemble_function_constructor_program`).
    pub(crate) source: String,
    /// Call-site resume context (reuses the deferred function-value-call
    /// completion machinery; mirrors `EvalRequest::completion`).
    pub(crate) completion: FunctionValueCallCompletion,
    /// Global object value: `Function(...)` always compiles in the global realm
    /// (`globalObject->globalScope()`, FunctionConstructor.cpp:166), so the
    /// wrapping function expression captures the global scope as `[[Scope]]`.
    pub(crate) global_this: RuntimeValue,
}

/// Build the program source for `Function(...)`, faithful to `stringifyFunction`
/// (FunctionConstructor.cpp:217-302) for FunctionConstructionMode::Function
/// (prefix `"function "`, name `"anonymous"`). `argument_strings` are the already
/// ToString'd arguments; the last is the body and the rest are the parameters.
///
/// DIVERGENCE: C++ `FunctionExecutable::fromGlobalCode` parses the bare
/// declaration program (`function anonymous(...) {...}`) through a dedicated
/// function-constructor parse mode and returns a `FunctionExecutable` directly.
/// The Rust port reuses the indirect-eval compile core
/// (`build_and_run_eval_code_block`), which evaluates a PROGRAM and yields its
/// completion value, so the declaration is wrapped in parentheses to become a
/// function EXPRESSION whose evaluation produces the function object without
/// running its body. The resulting closure is equivalent (global `[[Scope]]`,
/// name `"anonymous"`, body not executed).
fn assemble_function_constructor_program(argument_strings: &[String]) -> String {
    const PREFIX_AND_NAME: &str = "function anonymous";
    let program = match argument_strings.split_last() {
        // args.isEmpty(): "function anonymous(\n) {\n\n}"
        None => format!("{PREFIX_AND_NAME}(\n) {{\n\n}}"),
        Some((body, parameters)) => {
            if parameters.is_empty() {
                // args.size()==1 (body only): "function anonymous(\n) {\n<body>\n}"
                format!("{PREFIX_AND_NAME}(\n) {{\n{body}\n}}")
            } else {
                // args.size()>=2: "function anonymous(<p0>,<p1>,...\n) {\n<body>\n}"
                // (parameters comma-joined with no space, matching the C++ builder).
                let mut builder = String::from(PREFIX_AND_NAME);
                builder.push('(');
                builder.push_str(&parameters.join(","));
                builder.push_str("\n) {\n");
                builder.push_str(body);
                builder.push_str("\n}");
                builder
            }
        }
    };
    format!("({program})")
}

