#[derive(Clone, Debug, Default)]
pub struct ExecutionContextStack {
    entries: Vec<ActiveEntryFrame>,
    frames: Vec<InstalledCallFrame>,
    next_entry_id: u32,
    next_frame_id: u32,
}

impl ExecutionContextStack {
    pub fn entry_depth(&self) -> usize {
        self.entries.len()
    }

    pub fn frame_depth(&self) -> usize {
        self.frames.len()
    }

    pub fn active_entry(&self) -> Option<&ActiveEntryFrame> {
        self.entries.last()
    }

    pub fn top_frame(&self) -> Option<&InstalledCallFrame> {
        self.frames.last()
    }

    pub fn top_frame_mut(&mut self) -> Option<&mut InstalledCallFrame> {
        self.frames.last_mut()
    }

    pub fn active_global_this_value(&self) -> Result<RuntimeValue, ExecutionError> {
        if self.active_entry().is_none() {
            return Err(ExecutionError::NoActiveEntry);
        }
        for entry in self.entries.iter().rev() {
            match &entry.record {
                ExecutionEntryRecord::Program(program) => return Ok(program.this_value),
                ExecutionEntryRecord::Eval(eval) => return Ok(eval.this_value),
                ExecutionEntryRecord::Function(_) | ExecutionEntryRecord::Module(_) => {}
            }
        }
        Err(ExecutionError::ExpectedObject)
    }

    /// gc-r4 R4b ROOT GAP #2 — the global object(s) live on this stack as the
    /// `this` of each Program/Eval entry (`active_global_this_value` resolves the
    /// active one; the GC must root them ALL). JSC roots `JSGlobalObject` as a
    /// strong VM reference visited by `Heap::markRoots`; the port stores the global
    /// object as the program/eval entry `this_value`, so the safepoint gather walks
    /// the entries here. Rooting the global object transitively roots its butterfly,
    /// where every top-level `var`/`function` declaration and the builtin
    /// constructors live — so a missed global object = those swept = UAF on the next
    /// global property access. A Function entry's `this` is a register-file slot
    /// (`gather_vm_register_roots`); a Module entry's global `this` is `undefined`
    /// (the carried `this_value` is gathered regardless, harmlessly if not a cell).
    pub fn global_object_root_values(&self) -> Vec<RuntimeValue> {
        self.entries
            .iter()
            .filter_map(|entry| match &entry.record {
                ExecutionEntryRecord::Program(program) => Some(program.this_value),
                ExecutionEntryRecord::Eval(eval) => Some(eval.this_value),
                ExecutionEntryRecord::Function(_) | ExecutionEntryRecord::Module(_) => None,
            })
            .collect()
    }

    pub fn frame(&self, id: CallFrameId) -> Option<&InstalledCallFrame> {
        self.frames.iter().find(|frame| frame.id == id)
    }

    pub fn frames(&self) -> &[InstalledCallFrame] {
        &self.frames
    }

    pub fn enter(&mut self, record: ExecutionEntryRecord) -> EntryFrameId {
        self.next_entry_id = self.next_entry_id.saturating_add(1);
        let id = EntryFrameId(self.next_entry_id);
        let previous_entry = self.entries.last().map(|entry| entry.id);
        let saved_top_frame = self.frames.last().map(|frame| frame.id);
        self.entries.push(ActiveEntryFrame {
            id,
            record,
            previous_entry,
            saved_top_frame,
            pushed_frames: 0,
        });
        id
    }

    pub fn leave(&mut self, expected: EntryFrameId) -> Result<EntryExitRecord, ExecutionError> {
        let Some(entry) = self.entries.pop() else {
            return Err(ExecutionError::NoActiveEntry);
        };
        if entry.id != expected {
            self.entries.push(entry);
            return Err(ExecutionError::EntryMismatch {
                expected,
                actual: self.entries.last().map(|entry| entry.id),
            });
        }
        Ok(EntryExitRecord {
            entry: entry.id,
            kind: entry.record.kind(),
            restored_top_frame: entry.saved_top_frame,
            frame_count: entry.pushed_frames,
        })
    }

    pub fn push_frame(
        &mut self,
        registers: &mut RegisterFile,
        request: FramePushRequest,
        // K1: the registry's stable `*const CodeBlock` for `request.code_block`,
        // pre-resolved by the caller (it owns the `CodeBlockRegistry` / shared
        // `Rc`, which `ExecutionContextStack` — a sibling field of `Vm` — cannot
        // reach). Seeds call-frame slot 2 with a real `CodeBlock*`; `None` when
        // the frame has no code block or the caller has no registry (bare-stack
        // unit tests pass a synthetic sentinel or `None`).
        code_block_ptr: Option<*const CodeBlock>,
    ) -> Result<CallFrameId, ExecutionError> {
        if self.entries.is_empty() {
            return Err(ExecutionError::NoActiveEntry);
        }
        if request.argument_count_including_this == 0 {
            return Err(ExecutionError::InvalidArgumentCount);
        }

        self.next_frame_id = self.next_frame_id.saturating_add(1);
        let id = CallFrameId(self.next_frame_id);
        let caller = self.frames.last().map(|frame| frame.id);
        let window = registers.allocate_frame(
            id,
            request.shape,
            request.argument_count_including_this,
            &request.argument_values,
        )?;
        let frame = InstalledCallFrame {
            id,
            entry: self.entries.last().map(|entry| entry.id),
            caller,
            code_block: request.code_block,
            callee: request.callee,
            callee_value: request.callee_value,
            lexical_scope: request.lexical_scope,
            bytecode_index: request.start_bytecode_index,
            return_address: request.return_bytecode_index,
            return_continuation: None,
            argument_count_including_this: request.argument_count_including_this,
            register_window: window,
            state: FrameState::Executing,
        };
        if let Some(entry) = self.entries.last_mut() {
            entry.pushed_frames = entry.pushed_frames.saturating_add(1);
        }
        // B3 dual-write: mirror this frame's header + `this` + args into the
        // JsStack arena ALONGSIDE the `InstalledCallFrame`, with a debug
        // cross-check that the two agree. Behavior-neutral (reads stay on the
        // `Vec`); the arena is the substrate B4 flips reads onto. Driven here,
        // not in `allocate_frame`, because the header bits live on this frame.
        dual_write_shadow_frame(registers, &frame, &request.argument_values, code_block_ptr);
        self.frames.push(frame);
        Ok(id)
    }

    pub(crate) fn attach_return_continuation(
        &mut self,
        expected: CallFrameId,
        mut continuation: CallReturnContinuation,
    ) -> Result<CallReturnContinuation, ExecutionError> {
        let Some(frame) = self.frames.last_mut() else {
            return Err(ExecutionError::NoActiveFrame);
        };
        if frame.id != expected {
            return Err(ExecutionError::FrameMismatch {
                expected,
                actual: Some(frame.id),
            });
        }
        if continuation.callee_frame.is_some()
            || frame.caller != Some(continuation.caller_frame)
            || frame.return_continuation.is_some()
        {
            return Err(ExecutionError::InvalidCallContinuation);
        }
        continuation.callee_frame = Some(expected);
        frame.return_continuation = Some(continuation);
        Ok(continuation)
    }

    pub fn pop_frame(
        &mut self,
        registers: &mut RegisterFile,
        expected: CallFrameId,
    ) -> Result<InstalledCallFrame, ExecutionError> {
        let Some(frame) = self.frames.pop() else {
            return Err(ExecutionError::NoActiveFrame);
        };
        if frame.id != expected {
            self.frames.push(frame);
            return Err(ExecutionError::FrameMismatch {
                expected,
                actual: self.frames.last().map(|frame| frame.id),
            });
        }
        registers.release_frame(frame.register_window)?;
        Ok(frame)
    }

    pub fn unwind_to_entry(
        &mut self,
        registers: &mut RegisterFile,
        unwind: &mut ExceptionUnwindState,
    ) {
        while let Some(frame) = self.frames.pop() {
            let _ = registers.release_frame(frame.register_window);
            unwind.record_frame_popped(frame.id);
        }
    }

    pub fn unwind_through_frame(
        &mut self,
        registers: &mut RegisterFile,
        target: CallFrameId,
        unwind: &mut ExceptionUnwindState,
    ) {
        while let Some(frame) = self.frames.pop() {
            let id = frame.id;
            let _ = registers.release_frame(frame.register_window);
            unwind.record_frame_popped(id);
            if id == target {
                break;
            }
        }
    }

    pub fn mark_top_bytecode_index(&mut self, bytecode_index: BytecodeIndex) {
        if let Some(frame) = self.frames.last_mut() {
            frame.bytecode_index = Some(bytecode_index);
        }
    }

    pub fn root_snapshot(
        &self,
        heap: HeapId,
        registers: &RegisterFile,
    ) -> Result<ExecutionRootSnapshot, RootSetSemanticError> {
        let frame_roots = self
            .frames
            .iter()
            .flat_map(|frame| frame.root_descriptors(heap))
            .collect::<Vec<_>>();
        self.root_snapshot_with_frame_roots(heap, registers, frame_roots)
    }

    fn root_snapshot_with_frame_roots(
        &self,
        heap: HeapId,
        registers: &RegisterFile,
        frame_roots: Vec<FrameRootDescriptor>,
    ) -> Result<ExecutionRootSnapshot, RootSetSemanticError> {
        let register_roots = self
            .frames
            .iter()
            .flat_map(|frame| registers.root_descriptors_for_window(heap, frame.register_window))
            .collect::<Vec<_>>();
        validate_root_records(
            frame_roots
                .iter()
                .map(|descriptor| descriptor.root)
                .chain(register_roots.iter().map(|descriptor| descriptor.root)),
        )?;
        Ok(ExecutionRootSnapshot {
            frame_roots,
            register_roots,
        })
    }

    pub(crate) fn register_root_snapshot_for_slots(
        &self,
        heap: HeapId,
        registers: &RegisterFile,
        slots: &[(CallFrameId, usize)],
    ) -> Result<ExecutionRootSnapshot, RootSetSemanticError> {
        let register_roots = self
            .frames
            .iter()
            .flat_map(|frame| registers.root_descriptors_for_window(heap, frame.register_window))
            .filter(|descriptor| {
                slots
                    .iter()
                    .any(|(frame, slot)| descriptor.frame == *frame && descriptor.slot == *slot)
            })
            .collect::<Vec<_>>();
        validate_root_records(register_roots.iter().map(|descriptor| descriptor.root))?;
        Ok(ExecutionRootSnapshot {
            frame_roots: Vec::new(),
            register_roots,
        })
    }
}

/// Placeholder EntryFrame sentinel for slot 0 of a VM-entry frame (no JS
/// caller). JSC stores the real `EntryFrame*` here
/// (`callerFrameOrEntryFrame`, `interpreter/CallFrame.h:224`); the B3 shadow
/// encodes the abstract `EntryFrameId` under a high marker so it is
/// distinguishable from a real (large) arena caller address. Unobserved in B3
/// (the read-flip is B4); mirrors the sentinel style of B2's byte-identity test.
const ENTRY_FRAME_SHADOW_SENTINEL: u64 = 0x0000_7fff_0000_0000;

fn entry_frame_sentinel_bits(entry: Option<EntryFrameId>) -> u64 {
    ENTRY_FRAME_SHADOW_SENTINEL | u64::from(entry.map(|entry| entry.0).unwrap_or(0))
}

/// B3 dual-write: seed the arena shadow for a just-built `InstalledCallFrame`,
/// then (debug only) cross-check the arena image against it.
///
/// The arena slot encoding faithfully follows `doVMEntry`/`CallFrame.h:176-181`
/// given the live model's still-abstract identities (the divergence B6 retires):
/// - slot 0 (`callerFrameOrEntryFrame`): a real JS caller's arena address (a
///   genuinely linked frame chain), else the EntryFrame sentinel;
/// - slot 1 (`returnPC`): the return `BytecodeIndex` bits (real machine returnPC
///   is B7/JIT);
/// - slot 2 (`codeBlock`): the registry's stable `*const CodeBlock` address bits
///   (K1 — a real machine-dereferenceable `CodeBlock*`, not a `CellId`
///   placeholder), passed in as `code_block_ptr` resolved from the owning
///   `CodeBlockId` via `CodeBlockRegistry::code_block_pointer`; null when the
///   frame has no code block (host frames);
/// - slot 3 (`callee`): the `CellId` value as placeholder pointer bits (a real
///   `JSCell*` lands when cells are direct pointers, B6);
/// - slot 4 payload: `argumentCountIncludingThis`; tag (`CallSiteIndex`): 0;
/// - slot 5 + args: the `this`/argument values, byte-identical via their
///   NaN-boxed encoding.
fn dual_write_shadow_frame(
    registers: &mut RegisterFile,
    frame: &InstalledCallFrame,
    argument_values: &[RuntimeValue],
    code_block_ptr: Option<*const CodeBlock>,
) {
    let count = frame.argument_count_including_this;
    // `this` is window slot 0; `allocate_frame` fills `undefined` for any
    // under-supplied argument tail, so mirror the window exactly:
    // effective[k] = argument_values[k] else undefined.
    let effective = |k: usize| -> RuntimeValue {
        argument_values
            .get(k)
            .copied()
            .unwrap_or_else(RuntimeValue::undefined)
    };
    let this_value = JsStackRegister::from_encoded(effective(0).encoded());
    let arguments: Vec<JsStackRegister> = (1..count as usize)
        .map(|k| JsStackRegister::from_encoded(effective(k).encoded()))
        .collect();

    let caller_or_entry_bits = match frame.caller {
        Some(caller) => registers
            .shadow_address_of(caller)
            .map(|address| address.0 as u64)
            .unwrap_or(0),
        None => entry_frame_sentinel_bits(frame.entry),
    };
    let return_pc_bits = frame
        .return_address
        .map(|index| u64::from(index.as_bits()))
        .unwrap_or(0);
    // K1: slot 2 holds the registry's stable `*const CodeBlock` (the address bits
    // of the shared `Rc<CodeBlock>` box), NOT the `CellId` placeholder. The caller
    // resolves `frame.code_block` -> `CodeBlockRegistry::code_block_pointer` (or,
    // on the in-dispatch path, the same shared `Rc` the interpreter host holds)
    // and passes it in; null when the frame has no code block.
    let code_block_bits = code_block_ptr.map(|ptr| ptr as u64).unwrap_or(0);
    let callee_bits = frame
        .callee
        .map(|callee| u64::from(callee.0 .0))
        .unwrap_or(0);

    let seed = VmEntryFrameSeed {
        caller_frame_or_entry: JsStackRegister::from_bits(caller_or_entry_bits),
        return_pc: JsStackRegister::from_bits(return_pc_bits),
        code_block: JsStackRegister::from_bits(code_block_bits),
        callee: JsStackRegister::from_bits(callee_bits),
        argument_count_including_this: JsStackRegister::from_bits(u64::from(count)),
        this_value,
        arguments: &arguments,
        // The value-stack window allocates exactly `count` argument slots with no
        // alignment padding, so paddedArgCount == count (no `undefined` fill
        // beyond the supplied args).
        padded_argument_count: count,
        // B4 FULL-WINDOW: reserve + undefined-fill the callee's locals below `fp`,
        // exactly matching `allocate_frame`'s `local_count` (the `Vec` window's
        // local region), so every VirtualRegister the interpreter reads/writes has
        // an arena slot and nested callees never overlap this frame's locals.
        callee_local_count: frame.register_window.local_count as u32,
    };

    let Some(address) = registers.shadow_seed_frame(frame.id, &seed) else {
        return;
    };
    debug_assert_shadow_frame_matches(registers, frame, argument_values, address, code_block_ptr);
}

/// The B3 safety net (debug builds): assert the arena image read back through
/// the provenance gate is byte-identical to the live `InstalledCallFrame` for
/// the same frame. If the live model and the arena ever disagree, this fires —
/// this is what makes B4's read-flip sound. No-op in release.
fn debug_assert_shadow_frame_matches(
    registers: &RegisterFile,
    frame: &InstalledCallFrame,
    argument_values: &[RuntimeValue],
    address: FrameAddress,
    code_block_ptr: Option<*const CodeBlock>,
) {
    if !cfg!(debug_assertions) {
        return;
    }
    let Some(image) = registers.shadow_frame_header_image(address) else {
        return;
    };
    let expected_caller = match frame.caller {
        Some(caller) => registers
            .shadow_address_of(caller)
            .map(|address| address.0)
            .unwrap_or(0),
        None => entry_frame_sentinel_bits(frame.entry) as usize,
    };
    debug_assert_eq!(
        image.caller_frame_bits, expected_caller,
        "B3 shadow slot-0 (callerFrame/entry) disagrees with InstalledCallFrame",
    );
    debug_assert_eq!(
        image.return_pc_bits,
        frame
            .return_address
            .map(|index| index.as_bits() as usize)
            .unwrap_or(0),
        "B3 shadow returnPC slot disagrees with InstalledCallFrame",
    );
    // K1: slot 2 now holds the registry's `*const CodeBlock` bits, so cross-check
    // against the SAME resolved pointer the seed wrote (not the `CellId`).
    debug_assert_eq!(
        image.code_block_bits,
        code_block_ptr.map(|ptr| ptr as usize).unwrap_or(0),
        "B3 shadow codeBlock slot disagrees with the resolved CodeBlock*",
    );
    debug_assert_eq!(
        image.callee_bits,
        frame.callee.map(|callee| callee.0 .0 as usize).unwrap_or(0),
        "B3 shadow callee slot disagrees with InstalledCallFrame",
    );
    debug_assert_eq!(
        image.argument_count_including_this as u32, frame.argument_count_including_this,
        "B3 shadow argumentCountIncludingThis disagrees with InstalledCallFrame",
    );
    debug_assert_eq!(
        image.call_site_index_bits, 0,
        "B3 shadow slot-4 CallSiteIndex tag should be 0",
    );
    let this_expected = argument_values
        .first()
        .copied()
        .unwrap_or_else(RuntimeValue::undefined);
    debug_assert_eq!(
        image.this_value.js_value(),
        this_expected,
        "B3 shadow `this` disagrees with the frame's value",
    );
    for k in 1..frame.argument_count_including_this as usize {
        let expected = argument_values
            .get(k)
            .copied()
            .unwrap_or_else(RuntimeValue::undefined);
        let actual = registers.shadow_frame_argument_value(address, (k - 1) as i32);
        debug_assert_eq!(
            actual,
            Some(expected),
            "B3 shadow argument disagrees with the frame's value",
        );
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct ActiveEntryFrame {
    pub id: EntryFrameId,
    pub record: ExecutionEntryRecord,
    pub previous_entry: Option<EntryFrameId>,
    pub saved_top_frame: Option<CallFrameId>,
    pub pushed_frames: u32,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct EntryExitRecord {
    pub entry: EntryFrameId,
    pub kind: ExecutionEntryKind,
    pub restored_top_frame: Option<CallFrameId>,
    pub frame_count: u32,
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub enum ExecutionEntryRecord {
    Program(ProgramExecutionEntry),
    Function(FunctionExecutionEntry),
    Eval(EvalExecutionEntry),
    Module(ModuleExecutionEntry),
}

impl ExecutionEntryRecord {
    pub fn kind(&self) -> ExecutionEntryKind {
        match self {
            Self::Program(_) => ExecutionEntryKind::Program,
            Self::Function(_) => ExecutionEntryKind::Function,
            Self::Eval(_) => ExecutionEntryKind::Eval,
            Self::Module(_) => ExecutionEntryKind::Module,
        }
    }

    pub fn code_block(&self) -> CodeBlockId {
        match self {
            Self::Program(entry) => entry.code_block,
            Self::Function(entry) => entry.code_block,
            Self::Eval(entry) => entry.code_block,
            Self::Module(entry) => entry.code_block,
        }
    }

    pub fn entry_reason(&self) -> VmEntryReason {
        match self {
            Self::Module(_) => VmEntryReason::ModuleEvaluation,
            _ => VmEntryReason::Api,
        }
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum ExecutionEntryKind {
    Program,
    Function,
    Construct,
    Eval,
    Module,
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct ProgramExecutionEntry {
    pub code_block: CodeBlockId,
    pub global_object: GlobalObjectId,
    pub this_value: RuntimeValue,
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct FunctionExecutionEntry {
    pub code_block: CodeBlockId,
    pub function: ObjectId,
    pub this_value: RuntimeValue,
    pub context: Option<ObjectId>,
    pub argument_count: u32,
    pub specialization: CodeSpecializationKind,
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct EvalExecutionEntry {
    pub code_block: CodeBlockId,
    pub this_value: RuntimeValue,
    pub scope: ScopeId,
    pub direct: bool,
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct ModuleExecutionEntry {
    pub code_block: CodeBlockId,
    pub module_record: crate::modules::ModuleRecordId,
    pub module_environment: ObjectId,
    pub sent_value: RuntimeValue,
    pub resume_mode: RuntimeValue,
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct FramePushRequest {
    pub code_block: Option<CodeBlockId>,
    pub callee: Option<ObjectId>,
    pub callee_value: Option<RuntimeValue>,
    pub lexical_scope: Option<ScopeId>,
    pub shape: RegisterFrameShape,
    pub argument_count_including_this: u32,
    pub argument_values: Vec<RuntimeValue>,
    pub start_bytecode_index: Option<BytecodeIndex>,
    pub return_bytecode_index: Option<BytecodeIndex>,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum FrameState {
    Executing,
    Returning,
    Unwinding,
    Suspended,
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct InstalledCallFrame {
    pub id: CallFrameId,
    pub entry: Option<EntryFrameId>,
    pub caller: Option<CallFrameId>,
    pub code_block: Option<CodeBlockId>,
    pub callee: Option<ObjectId>,
    pub callee_value: Option<RuntimeValue>,
    pub lexical_scope: Option<ScopeId>,
    pub bytecode_index: Option<BytecodeIndex>,
    pub return_address: Option<BytecodeIndex>,
    pub return_continuation: Option<CallReturnContinuation>,
    pub argument_count_including_this: u32,
    pub register_window: RegisterWindow,
    pub state: FrameState,
}

impl InstalledCallFrame {
    pub fn as_frame_record(&self) -> InterpreterFrameRecord {
        InterpreterFrameRecord {
            frame: Some(self.id),
            entry_frame: self.entry,
            kind: Some(InterpreterFrameKind::JavaScript),
            code_block: self.code_block,
            bytecode_index: self.bytecode_index,
            callee: self.callee,
            lexical_scope: self.lexical_scope,
        }
    }

    pub fn root_descriptors(&self, heap: HeapId) -> Vec<FrameRootDescriptor> {
        self.root_descriptors_with_policy(heap, |_| FrameRootTarget::unknown())
    }

    fn root_descriptors_with_policy<F>(
        &self,
        heap: HeapId,
        target_for_cell: F,
    ) -> Vec<FrameRootDescriptor>
    where
        F: Fn(CellId) -> FrameRootTarget,
    {
        let mut roots = Vec::new();
        if let Some(code_block) = self.code_block {
            roots.push(FrameRootDescriptor::new(
                heap,
                self.id,
                FrameRootSource::CodeBlock,
                target_for_cell(code_block.0),
            ));
        }
        if let Some(callee) = self.callee {
            roots.push(FrameRootDescriptor::new(
                heap,
                self.id,
                FrameRootSource::Callee,
                target_for_cell(callee.0),
            ));
        }
        if self.lexical_scope.is_some() {
            roots.push(FrameRootDescriptor::new(
                heap,
                self.id,
                FrameRootSource::LexicalScope,
                FrameRootTarget::no_target(),
            ));
        }
        roots
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum FrameRootSource {
    CodeBlock,
    Callee,
    LexicalScope,
}

impl FrameRootSource {
    const fn ordinal(self) -> u64 {
        match self {
            Self::CodeBlock => 1,
            Self::Callee => 2,
            Self::LexicalScope => 3,
        }
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum FrameRootTarget {
    Known(CellId),
    NoTarget,
    Unknown,
}

impl FrameRootTarget {
    pub const fn known(target: CellId) -> Self {
        Self::Known(target)
    }

    pub const fn no_target() -> Self {
        Self::NoTarget
    }

    pub const fn unknown() -> Self {
        Self::Unknown
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct FrameRootDescriptor {
    pub root: RootRecord,
    pub frame: CallFrameId,
    pub source: FrameRootSource,
    pub target: FrameRootTarget,
}

impl FrameRootDescriptor {
    fn new(
        heap: HeapId,
        frame: CallFrameId,
        source: FrameRootSource,
        target: FrameRootTarget,
    ) -> Self {
        Self {
            root: RootRecord {
                id: frame_root_id(frame, source),
                kind: RootKind::VMRegister,
                heap,
            },
            frame,
            source,
            target,
        }
    }
}

/// Lifecycle of the B3 JsStack dual-write shadow owned by a [`RegisterFile`].
///
/// The shadow is created LAZILY (the 5 MiB arena mmap is only reserved once a
/// frame is actually pushed) and, once disabled, stays disabled (no retry).
/// Disabling is how the dual-write stays BEHAVIOR-NEUTRAL: any arena problem
/// (overflow, mmap failure, LIFO desync) drops the arena instead of changing
/// control flow. This is a small Rust-port bridge state machine; JSC has no
/// counterpart because there the native stack IS the only frame store.
///
/// `RegisterFile` cannot derive `Clone`/`Eq`/`PartialEq` once it owns this
/// (the arena's `mmap` reservation is unique, non-cloneable, non-comparable);
/// those derives were unused. `Default` is retained: an unpushed register file
/// starts `Uninitialized`.
#[derive(Debug, Default)]
enum ShadowState {
    /// No arena reserved yet (lazy); the next push attempts creation.
    #[default]
    Uninitialized,
    /// A live arena mirroring the current frame stack.
    Active(Box<JsStackShadow>),
    /// Creation failed or a fault disabled it; the dual-write is a permanent
    /// no-op for this register file.
    Disabled,
}

#[derive(Debug, Default)]
pub struct RegisterFile {
    values: Vec<RuntimeValue>,
    windows: Vec<RegisterWindow>,
    // C++ JSC divergence (B3 dual-write bridge): the JsStack arena shadow. The
    // native-thread-stack arena (`vm::jsstack`) is the faithful realization of
    // the JS value stack that this `RegisterFile` abstracts; B3 mirrors every
    // pushed frame's header + `this` + args into it ALONGSIDE the live
    // `values`/`windows`, so B4 can flip `read`/`write` to address the arena.
    // Reads are UNCHANGED in B3 (still `values`); the mirror is unobserved and
    // behavior-neutral. See `ShadowState` and `dual_write_shadow_frame`.
    shadow: ShadowState,
    // C++ JSC divergence: C++ JSC does ZERO per-bytecode rooting. The LLInt
    // dispatch macro just advances PC and jumps
    // (llint/LowLevelInterpreter.asm dispatch); a value is rooted simply by
    // being live in a register/stack slot, and the whole live register-file
    // span is conservatively scanned ONCE per GC at a safepoint
    // (interpreter/CLoopStack.cpp:111 gatherConservativeRoots adds
    // currentStackPointer..highAddress; heap/Heap.cpp:903 gatherStackRoots under
    // worldIsStopped, :3021), so rooting cost is O(stack) once per GC, not per
    // op. The Rust port now matches that model: there is NO per-store root
    // bookkeeping; `gather_vm_register_roots` walks this whole live backing
    // store at the safepoint poll points (D2i). The retired
    // `cell_root_dirty`/`CellRootDirty` signal and the per-op targeted-root
    // registry it drove were the prior Rust-only approximation of the safepoint
    // model and have been removed.
}

// Manual `Clone` (the derive cannot see through the `mmap`-backed shadow arena).
// The JsStack dual-write shadow is a UNIQUE, non-cloneable bridge: its arena is
// one mmap reservation, so a clone CANNOT share or duplicate it. A cloned
// register file therefore starts a FRESH shadow (`Uninitialized`) and lazily
// reserves its own arena on its next push. Clone copies the logical value-stack
// state (`values`/`windows`); the shadow is a transient, unobserved B3 mirror
// (reads still come from `values`), so resetting it on clone is behavior-neutral.
// `Eq`/`PartialEq` were dropped with the derive — they were unused and cannot
// hold for the arena anyway.
impl Clone for RegisterFile {
    fn clone(&self) -> Self {
        RegisterFile {
            values: self.values.clone(),
            windows: self.windows.clone(),
            shadow: ShadowState::Uninitialized,
        }
    }
}

impl RegisterFile {
    pub fn register_count(&self) -> usize {
        self.values.len()
    }

    /// Encode the whole live register backing store as a value-stack snapshot
    /// for the safepoint root gather (`gather_vm_register_roots`).
    ///
    /// `values` is the contiguous concatenation of every live window's locals
    /// then arguments (`allocate_frame` grows `values` by `local_count` and then
    /// pushes the argument slots; `release_frame` truncates back to the window
    /// base), so there are no gaps and a slot's position in `values` is exactly
    /// the absolute register-file slot index that `register_root_id` keys on.
    /// This is the Rust analog of `CLoopStack::gatherConservativeRoots` adding
    /// the live `currentStackPointer..highAddress` span once at GC time
    /// (interpreter/CLoopStack.cpp:111-114).
    pub(crate) fn live_value_stack_snapshot(
        &self,
    ) -> Result<ValueStackSnapshot, ValueStackConversionError> {
        encode_value_stack(&self.values)
    }

    pub fn active_windows(&self) -> &[RegisterWindow] {
        &self.windows
    }

    /// Borrows the current top register window as active-frame authority.
    ///
    /// Generated and native helpers may carry copied `RegisterWindow`
    /// descriptors, but must validate that descriptor against the VM-owned top
    /// frame before using it for register access.
    pub(crate) fn active_window_authority(
        &self,
        expected_frame: CallFrameId,
        window: RegisterWindow,
    ) -> Result<ActiveRegisterWindowAuthority<'_>, ExecutionError> {
        let window = self.validate_active_window(expected_frame, window)?;
        Ok(ActiveRegisterWindowAuthority {
            registers: self,
            frame: expected_frame,
            window,
        })
    }

    /// Mutably borrows the current top register window as active-frame authority.
    ///
    /// Writes through this guard still use `RegisterFile::write`, preserving the
    /// existing interpreter write-barrier handoff behavior.
    pub(crate) fn active_window_authority_mut(
        &mut self,
        expected_frame: CallFrameId,
        window: RegisterWindow,
    ) -> Result<ActiveRegisterWindowAuthorityMut<'_>, ExecutionError> {
        let window = self.validate_active_window(expected_frame, window)?;
        Ok(ActiveRegisterWindowAuthorityMut {
            registers: self,
            frame: expected_frame,
            window,
        })
    }

    pub fn root_descriptors(&self, heap: HeapId) -> Vec<RegisterRootDescriptor> {
        self.windows
            .iter()
            .flat_map(|window| self.root_descriptors_for_window(heap, *window))
            .collect()
    }

    fn root_descriptors_for_window(
        &self,
        heap: HeapId,
        window: RegisterWindow,
    ) -> Vec<RegisterRootDescriptor> {
        let locals = (0..window.local_count).filter_map(|offset| {
            self.register_root_descriptor(
                heap,
                window,
                window.base.saturating_add(offset),
                RegisterSlotKind::Local,
            )
        });
        let arguments = (0..window.argument_count).filter_map(|offset| {
            self.register_root_descriptor(
                heap,
                window,
                window.argument_base.saturating_add(offset),
                RegisterSlotKind::Argument,
            )
        });
        locals.chain(arguments).collect()
    }

    pub fn allocate_frame(
        &mut self,
        owner: CallFrameId,
        shape: RegisterFrameShape,
        argument_count_including_this: u32,
        argument_values: &[RuntimeValue],
    ) -> Result<RegisterWindow, ExecutionError> {
        let argument_count = usize::try_from(argument_count_including_this)
            .map_err(|_| ExecutionError::RegisterCapacityExceeded)?;
        if argument_values.len() > argument_count {
            return Err(ExecutionError::InvalidArgumentCount);
        }
        let local_count = usize::try_from(frame_local_capacity(shape))
            .map_err(|_| ExecutionError::RegisterCapacityExceeded)?;
        let base = self.values.len();
        self.values
            .resize(base.saturating_add(local_count), RuntimeValue::undefined());
        let argument_base = self.values.len();
        for index in 0..argument_count {
            let value = argument_values
                .get(index)
                .copied()
                .unwrap_or_else(RuntimeValue::undefined);
            self.values.push(value);
        }
        let window = RegisterWindow {
            owner,
            base,
            local_count,
            argument_base,
            argument_count,
            this_offset: CallFrameSlotLayout::JSC_RUST.this_argument_offset,
        };
        self.windows.push(window);
        // C++ JSC does no per-store/per-frame root bookkeeping: the newly
        // established window's slots become roots simply by being live in the
        // register file, which the GC-time safepoint scan
        // (`gather_vm_register_roots`, the analog of
        // CLoopStack::gatherConservativeRoots) walks in full. No dirty signal is
        // recorded here (D2i).
        Ok(window)
    }

    pub fn release_frame(&mut self, window: RegisterWindow) -> Result<(), ExecutionError> {
        let Some(active) = self.windows.pop() else {
            return Err(ExecutionError::NoActiveFrame);
        };
        if active != window {
            self.windows.push(active);
            return Err(ExecutionError::RegisterWindowMismatch);
        }
        self.values.truncate(window.base);
        // C++ JSC scans the live call-frame span at a GC safepoint; popping the
        // top frame does not make the surviving caller frame dirty. Rust's
        // precise targeted-root bridge therefore cleans the popped frame through
        // the frame/root owner, not by forcing the next caller entry to rescan a
        // full surviving window. A returned cell still dirties the caller
        // through `write`, below, because that is an actual caller-slot change.
        //
        // B3 dual-write: raise the arena SP in lockstep with this value-stack
        // truncation. This single mirror point covers EVERY frame release path
        // (`pop_frame`, `unwind_to_entry`, `unwind_through_frame`), keeping the
        // arena a faithful shadow across the whole call tree.
        self.shadow_release_frame(window.owner);
        Ok(())
    }

    // --- B3 JsStack dual-write shadow (behavior-neutral; reads stay on `values`) ---

    /// Seed the arena shadow for a freshly pushed frame, mirroring its header +
    /// `this` + args alongside the live `InstalledCallFrame`. Lazily creates the
    /// arena on first use. Any arena refusal (overflow / bad args) DISABLES the
    /// shadow rather than affecting control flow (B3 is behavior-neutral).
    /// Returns the seeded arena [`FrameAddress`], or `None` if the shadow is
    /// inactive/disabled.
    fn shadow_seed_frame(
        &mut self,
        frame_id: CallFrameId,
        seed: &VmEntryFrameSeed<'_>,
    ) -> Option<FrameAddress> {
        if matches!(self.shadow, ShadowState::Uninitialized) {
            self.shadow = match JsStackShadow::new() {
                Some(shadow) => ShadowState::Active(Box::new(shadow)),
                None => ShadowState::Disabled,
            };
        }
        let ShadowState::Active(shadow) = &mut self.shadow else {
            return None;
        };
        match shadow.seed_frame(frame_id.0, seed) {
            Some(address) => Some(address),
            None => {
                // The arena could not hold this frame (e.g. deep recursion past
                // the 5 MiB limit, exactly where JSC throws a stack overflow).
                // Drop the arena and stop mirroring; the live `Vec` model keeps
                // running, so behavior is unchanged.
                self.shadow = ShadowState::Disabled;
                None
            }
        }
    }

    /// Mirror a frame release into the arena (raise SP). A non-LIFO release
    /// (only possible if a frame was created off the `push_frame` path) DISABLES
    /// the shadow rather than panicking.
    fn shadow_release_frame(&mut self, frame_id: CallFrameId) {
        let ShadowState::Active(shadow) = &mut self.shadow else {
            return;
        };
        if shadow.release_frame(frame_id.0).is_err() {
            self.shadow = ShadowState::Disabled;
        }
    }

    /// Forward side-table lookup: live `CallFrameId` -> arena `FrameAddress`.
    pub(crate) fn shadow_address_of(&self, frame_id: CallFrameId) -> Option<FrameAddress> {
        match &self.shadow {
            ShadowState::Active(shadow) => shadow.address_of(frame_id.0),
            _ => None,
        }
    }

    /// Reverse side-table lookup: arena `FrameAddress` -> live `CallFrameId`.
    ///
    /// B3/B4/B6 bridge-inspection API: the reverse half of the
    /// `CallFrameId <-> FrameAddress` round-trip (B6 consumes it to translate an
    /// arena `CallFrame*` back to the live identity), exercised by the B3 test.
    #[allow(dead_code)]
    pub(crate) fn shadow_frame_id_at(&self, address: FrameAddress) -> Option<CallFrameId> {
        match &self.shadow {
            ShadowState::Active(shadow) => shadow.frame_id_at(address).map(CallFrameId),
            _ => None,
        }
    }

    /// Number of currently-mirrored frames in the arena shadow. Bridge-inspection
    /// API exercised by the B3 lockstep test.
    #[allow(dead_code)]
    pub(crate) fn shadow_depth(&self) -> usize {
        match &self.shadow {
            ShadowState::Active(shadow) => shadow.depth(),
            _ => 0,
        }
    }

    /// The arena's current stack pointer (for the lockstep-SP cross-check), or
    /// `None` if the shadow is inactive. Bridge-inspection API exercised by the
    /// B3 lockstep test.
    #[allow(dead_code)]
    pub(crate) fn shadow_current_stack_pointer(&self) -> Option<usize> {
        match &self.shadow {
            ShadowState::Active(shadow) => Some(shadow.current_stack_pointer()),
            _ => None,
        }
    }

    /// Read back a mirrored frame's header + `this` for the cross-check.
    pub(crate) fn shadow_frame_header_image(
        &self,
        address: FrameAddress,
    ) -> Option<crate::vm::jsstack::ShadowFrameImage> {
        match &self.shadow {
            ShadowState::Active(shadow) => shadow.frame_header_image(address),
            _ => None,
        }
    }

    /// K1: recover a mirrored frame's slot 2 (`codeBlock`) as a real
    /// `*const CodeBlock` — the cfr-relative `[fp+16]` read the op_call/JIT
    /// recovery path uses. Additive (no caller yet); see
    /// [`crate::vm::jsstack::JsStackShadow::frame_code_block_ptr`] for the
    /// pointer's stability/dereferenceability contract.
    #[allow(dead_code)]
    pub(crate) fn shadow_frame_code_block_ptr(
        &self,
        address: FrameAddress,
    ) -> Option<*const CodeBlock> {
        match &self.shadow {
            ShadowState::Active(shadow) => shadow.frame_code_block_ptr(address),
            _ => None,
        }
    }

    /// Read back a mirrored frame's argument `index` (excluding `this`) as a
    /// decoded value, for the cross-check.
    pub(crate) fn shadow_frame_argument_value(
        &self,
        address: FrameAddress,
        index: i32,
    ) -> Option<RuntimeValue> {
        match &self.shadow {
            ShadowState::Active(shadow) => shadow
                .frame_argument(address, index)
                .map(|reg| reg.js_value()),
            _ => None,
        }
    }

    #[allow(dead_code)]
    pub(crate) fn borrow_active_frame_base_for_raw_native_entry(
        &mut self,
        window: RegisterWindow,
    ) -> Result<RawNativeFrameBaseBorrow<'_>, ExecutionError> {
        let active = self.validate_active_window(window.owner, window)?;
        if active.local_count == 0 {
            return Err(ExecutionError::RegisterOutOfBounds);
        }

        // B4 READ-FLIP: raw native (P3b/P6) code writes this frame's slots
        // through the returned raw pointer, BYPASSING `RegisterFile::write`, so
        // the arena window cannot observe those stores and would go stale under
        // it. Until B7 wires the JIT to emit FP-relative loads/stores directly
        // against the arena, DISABLE the shadow on this path: `read` then falls
        // back to the `Vec` oracle, keeping the read-flip cross-check sound and
        // behavior identical. Disable BEFORE taking the mutable `values` borrow
        // (which extends `&mut self` for the borrow's lifetime).
        self.shadow = ShadowState::Disabled;

        let first_local = self
            .values
            .get_mut(active.base)
            .ok_or(ExecutionError::RegisterOutOfBounds)?;
        debug_assert_eq!(std::mem::size_of::<RuntimeValue>(), 8);
        // Raw native P3b/P6 bytes address frame locals as positive 8-byte
        // slots from this base. Keep pointer erasure centralized here by first
        // taking a checked mutable reference to `values[window.base]`.
        let ptr = NonNull::from(first_local).cast::<c_void>();
        Ok(RawNativeFrameBaseBorrow {
            ptr,
            _register_file: PhantomData,
        })
    }

    pub fn read(
        &self,
        window: RegisterWindow,
        register: VirtualRegister,
        constants: Option<&LinkedConstantPool>,
    ) -> Result<RuntimeValue, ExecutionError> {
        if let Some(index) = register.to_constant_index() {
            return read_constant(constants, index);
        }
        let slot = self.resolve_value_slot(window, register)?;
        let vec_value = self
            .values
            .get(slot)
            .copied()
            .ok_or(ExecutionError::RegisterOutOfBounds)?;
        // B4 READ-FLIP: the JsStack arena window is now the live register store.
        // When the shadow is active, read the `Register` from the arena via the
        // provenance gate at `fp + vreg.raw()*8` and return THAT — faithful to
        // `AssemblyHelpers::addressFor(vreg) = Address(x29, vreg.offset()*8)`
        // (`AssemblyHelpers.h:1290-1298`), the FP-relative addressing the baseline
        // JIT bakes into emitted loads. The `Vec` is retained as a debug ORACLE:
        // `arena == Vec` is asserted for EVERY read (locals/temporaries included),
        // so an off-by-one or sign error in the offset mapping fires immediately
        // (the same cross-check discipline as B3, now over the full window). This
        // keeps B4 REVERSIBLE; a follow-up (B4b/B6) drops the `Vec`. When the
        // shadow is inactive/disabled (deep-recursion overflow past the 5 MiB
        // arena, mmap failure, non-unix, or the raw-native bypass), reads fall
        // back to the `Vec` so behavior is identical.
        match self.arena_read_value(window, register) {
            Some(arena_value) => {
                debug_assert_eq!(
                    arena_value, vec_value,
                    "B4 arena read disagrees with the Vec oracle at {register:?} \
                     (window {window:?}) — arena offset mapping is wrong",
                );
                Ok(arena_value)
            }
            None => Ok(vec_value),
        }
    }

    pub fn write(
        &mut self,
        window: RegisterWindow,
        register: VirtualRegister,
        value: RuntimeValue,
    ) -> Result<(), ExecutionError> {
        if register.is_constant() {
            return Err(ExecutionError::CannotWriteConstant);
        }
        let slot = self.resolve_value_slot(window, register)?;
        let Some(target) = self.values.get_mut(slot) else {
            return Err(ExecutionError::RegisterOutOfBounds);
        };
        // C++ JSC divergence (removed): a register/stack store does NOT emit a
        // write barrier in C++ JSC. op_mov and every plain virtual-register
        // store just write the slot (llint/LowLevelInterpreter64.asm op_mov
        // -> storeValue; jit/JITOpcodes.cpp:51 emit_op_mov -> storeValue), with
        // no barrierBranch / operationWriteBarrierSlowPath. The generational
        // write barrier is only for HEAP-OBJECT FIELD stores keyed on the base
        // cell (jit/JITPropertyAccess.cpp:771 op_put_by_id -> emitWriteBarrier,
        // :1827 op_put_by_val, :1613/:1638/:1654 op_put_to_scope), because the
        // GC must remember old->young CELL edges in the heap. The JS register
        // file / call frame is a GC ROOT, conservatively span-scanned at GC
        // safepoints (interpreter/CLoopStack.cpp:113 gatherConservativeRoots,
        // heap/Heap.cpp:903 gatherStackRoots), so stack/register stores need no
        // barrier. The prior per-write barrier-schema evaluation and the
        // InterpreterWriteBarrierRecord accumulation therefore had no C++
        // counterpart, were never drained or consumed by any runtime logic, and
        // cost ~1.2us per register write; both are removed. The real heap-field
        // barriers live in apply_value_store_write_barrier /
        // put_data_own_with_write_barrier / put_array_element_with_write_barrier
        // and are independent of this method and untouched.
        //
        // C++ JSC divergence (D2i): a register store does NO root bookkeeping
        // either. The slot is a GC root by virtue of being live in the register
        // file; the GC-time safepoint scan (`gather_vm_register_roots`, the
        // analog of CLoopStack::gatherConservativeRoots) walks the whole live
        // span once per collection. The prior per-store
        // `cell_root_dirty.widen_slot` trigger -- which drove a per-op
        // targeted-root registry recompute and was the #1 measured interpreter
        // self-time tax -- has been removed.
        *target = value;
        // B4 READ-FLIP: the arena window is the live register store, so mirror
        // this store into it at `fp + vreg.raw()*8` (the new truth that `read`
        // returns), keeping the `Vec` above as the cross-checked oracle. No-op
        // when the shadow is inactive/disabled (reversible, behavior-neutral).
        self.arena_write_value(window, register, value);
        Ok(())
    }

    /// B4 read-flip: read `register`'s value from the JsStack arena window of
    /// `window.owner`, or `None` if the shadow is inactive (then `read` uses the
    /// `Vec`). The arena address is `fp + register.raw()*8` via the gate; the bits
    /// decode losslessly because `RuntimeValue` is a `repr(transparent)` wrapper
    /// over the same `EncodedJsValue` a `Register` stores.
    fn arena_read_value(
        &self,
        window: RegisterWindow,
        register: VirtualRegister,
    ) -> Option<RuntimeValue> {
        let ShadowState::Active(shadow) = &self.shadow else {
            return None;
        };
        let fp = shadow.address_of(window.owner.0)?;
        let reg = shadow.frame_register_at(fp, register.raw())?;
        Some(reg.js_value())
    }

    /// B4 read-flip: mirror a `register` store into the JsStack arena window of
    /// `window.owner` (the dual-write half of [`Self::arena_read_value`]). No-op
    /// when the shadow is inactive/disabled. `resolve_value_slot` already bounded
    /// `register` to this frame's reserved window, so the gate write succeeds.
    fn arena_write_value(
        &self,
        window: RegisterWindow,
        register: VirtualRegister,
        value: RuntimeValue,
    ) {
        let ShadowState::Active(shadow) = &self.shadow else {
            return;
        };
        if let Some(fp) = shadow.address_of(window.owner.0) {
            let reg = JsStackRegister::from_encoded(value.encoded());
            shadow.write_frame_register(fp, register.raw(), reg);
        }
    }

    pub(crate) fn validate_writable_register(
        &self,
        window: RegisterWindow,
        register: VirtualRegister,
    ) -> Result<(), ExecutionError> {
        if register.is_constant() {
            return Err(ExecutionError::CannotWriteConstant);
        }
        self.resolve_value_slot(window, register).map(|_| ())
    }

    fn resolve_value_slot(
        &self,
        window: RegisterWindow,
        register: VirtualRegister,
    ) -> Result<usize, ExecutionError> {
        if !register.is_valid() {
            return Err(ExecutionError::InvalidRegister);
        }
        if let Some(index) = register.to_local_index() {
            let index = usize::try_from(index).map_err(|_| ExecutionError::RegisterOutOfBounds)?;
            if index >= window.local_count {
                return Err(ExecutionError::RegisterOutOfBounds);
            }
            return Ok(window.base + index);
        }
        if register.is_argument_or_header() {
            let raw = register.raw();
            if raw < window.this_offset.0 {
                return Err(ExecutionError::CannotAddressHeaderAsValue);
            }
            let index = usize::try_from(raw - window.this_offset.0)
                .map_err(|_| ExecutionError::RegisterOutOfBounds)?;
            if index >= window.argument_count {
                return Err(ExecutionError::RegisterOutOfBounds);
            }
            return Ok(window.argument_base + index);
        }
        Err(ExecutionError::InvalidRegister)
    }

    fn validate_active_window(
        &self,
        expected_frame: CallFrameId,
        window: RegisterWindow,
    ) -> Result<RegisterWindow, ExecutionError> {
        let Some(active) = self.windows.last().copied() else {
            return Err(ExecutionError::NoActiveFrame);
        };
        if active != window {
            return Err(ExecutionError::RegisterWindowMismatch);
        }
        if active.owner != expected_frame {
            return Err(ExecutionError::FrameMismatch {
                expected: expected_frame,
                actual: Some(active.owner),
            });
        }
        Self::checked_register_range_end(active.base, active.local_count, self.values.len())?;
        Self::checked_register_range_end(
            active.argument_base,
            active.argument_count,
            self.values.len(),
        )?;
        Ok(active)
    }

    fn checked_register_range_end(
        base: usize,
        count: usize,
        value_count: usize,
    ) -> Result<usize, ExecutionError> {
        let end = base
            .checked_add(count)
            .ok_or(ExecutionError::RegisterOutOfBounds)?;
        if end > value_count {
            return Err(ExecutionError::RegisterOutOfBounds);
        }
        Ok(end)
    }

    fn register_root_descriptor(
        &self,
        heap: HeapId,
        window: RegisterWindow,
        slot: usize,
        slot_kind: RegisterSlotKind,
    ) -> Option<RegisterRootDescriptor> {
        self.values
            .get(slot)
            .copied()
            .map(|value| RegisterRootDescriptor {
                root: RootRecord {
                    id: register_root_id(slot),
                    kind: RootKind::VMRegister,
                    heap,
                },
                frame: window.owner,
                slot,
                slot_kind,
                value,
                cell_payload: value_cell_payload(value),
            })
    }
}

#[derive(Debug)]
#[must_use = "keep this authority alive while using the active register window"]
pub(crate) struct ActiveRegisterWindowAuthority<'a> {
    registers: &'a RegisterFile,
    frame: CallFrameId,
    window: RegisterWindow,
}

impl ActiveRegisterWindowAuthority<'_> {
    #[allow(dead_code)]
    pub(crate) fn frame(&self) -> CallFrameId {
        self.frame
    }

    #[allow(dead_code)]
    pub(crate) fn window(&self) -> RegisterWindow {
        self.window
    }

    pub(crate) fn read(
        &self,
        register: VirtualRegister,
        constants: Option<&LinkedConstantPool>,
    ) -> Result<RuntimeValue, ExecutionError> {
        self.registers.read(self.window, register, constants)
    }
}

#[derive(Debug)]
#[must_use = "keep this authority alive while using the active register window"]
pub(crate) struct ActiveRegisterWindowAuthorityMut<'a> {
    registers: &'a mut RegisterFile,
    frame: CallFrameId,
    window: RegisterWindow,
}

impl ActiveRegisterWindowAuthorityMut<'_> {
    #[allow(dead_code)]
    pub(crate) fn frame(&self) -> CallFrameId {
        self.frame
    }

    #[allow(dead_code)]
    pub(crate) fn window(&self) -> RegisterWindow {
        self.window
    }

    #[allow(dead_code)]
    pub(crate) fn read(
        &self,
        register: VirtualRegister,
        constants: Option<&LinkedConstantPool>,
    ) -> Result<RuntimeValue, ExecutionError> {
        self.registers.read(self.window, register, constants)
    }

    pub(crate) fn write(
        &mut self,
        register: VirtualRegister,
        value: RuntimeValue,
    ) -> Result<(), ExecutionError> {
        self.registers.write(self.window, register, value)
    }
}

#[allow(dead_code)]
#[derive(Debug)]
#[must_use = "keep this guard alive while raw native code uses the frame-base pointer"]
pub(crate) struct RawNativeFrameBaseBorrow<'a> {
    ptr: NonNull<c_void>,
    _register_file: PhantomData<&'a mut RegisterFile>,
}

#[allow(dead_code)]
impl RawNativeFrameBaseBorrow<'_> {
    /// Opaque pointer to the active frame's first local slot.
    ///
    /// The pointer remains valid only while this guard is alive. Holding the
    /// guard keeps `RegisterFile` mutably borrowed, preventing safe callers
    /// from allocating or releasing register frames during the raw native call.
    pub(crate) fn as_non_null(&self) -> NonNull<c_void> {
        self.ptr
    }
}

pub(crate) fn create_call_return_continuation(
    stack: &ExecutionContextStack,
    registers: &RegisterFile,
    heap: &Heap,
    request: CallReturnContinuationRequest,
) -> Result<CallReturnContinuation, ExecutionError> {
    if request.argument_count_including_this == 0 {
        return Err(ExecutionError::InvalidArgumentCount);
    }
    if !request.call_bytecode_index.is_valid() {
        return Err(ExecutionError::InvalidBytecodeIndex(
            request.call_bytecode_index,
        ));
    }
    if let Some(resume) = request.resume_bytecode_index {
        if !resume.is_valid() {
            return Err(ExecutionError::InvalidBytecodeIndex(resume));
        }
    }

    let Some(frame) = stack.top_frame() else {
        return Err(ExecutionError::NoActiveFrame);
    };
    if frame.id != request.caller_frame {
        return Err(ExecutionError::FrameMismatch {
            expected: request.caller_frame,
            actual: Some(frame.id),
        });
    }
    if frame.code_block != Some(request.owner) {
        return Err(ExecutionError::CodeBlockMismatch {
            expected: request.owner,
            actual: frame.code_block,
        });
    }
    if frame.register_window != request.caller_window {
        return Err(ExecutionError::RegisterWindowMismatch);
    }

    let _ = registers.active_window_authority(request.caller_frame, request.caller_window)?;
    registers.validate_writable_register(request.caller_window, request.destination)?;

    Ok(CallReturnContinuation {
        caller_frame: request.caller_frame,
        callee_frame: None,
        owner: request.owner,
        call_bytecode_index: request.call_bytecode_index,
        resume_bytecode_index: request.resume_bytecode_index,
        destination: request.destination,
        argument_count_including_this: request.argument_count_including_this,
        callee_value: request.callee_value,
        callee_object: request
            .callee_value
            .and_then(value_cell_payload)
            .and_then(|payload| heap.cell_for_payload(payload))
            .map(ObjectId),
        kind: request.kind,
    })
}

pub(crate) fn create_construct_return_continuation(
    stack: &ExecutionContextStack,
    registers: &RegisterFile,
    heap: &Heap,
    request: ConstructReturnContinuationRequest,
) -> Result<ConstructReturnContinuation, ExecutionError> {
    if request.argument_count_including_this == 0 {
        return Err(ExecutionError::InvalidArgumentCount);
    }
    if !request.construct_bytecode_index.is_valid() {
        return Err(ExecutionError::InvalidBytecodeIndex(
            request.construct_bytecode_index,
        ));
    }
    if let Some(resume) = request.resume_bytecode_index {
        if !resume.is_valid() {
            return Err(ExecutionError::InvalidBytecodeIndex(resume));
        }
    }

    let Some(frame) = stack.top_frame() else {
        return Err(ExecutionError::NoActiveFrame);
    };
    if frame.id != request.caller_frame {
        return Err(ExecutionError::FrameMismatch {
            expected: request.caller_frame,
            actual: Some(frame.id),
        });
    }
    if frame.code_block != Some(request.owner) {
        return Err(ExecutionError::CodeBlockMismatch {
            expected: request.owner,
            actual: frame.code_block,
        });
    }
    if frame.register_window != request.caller_window {
        return Err(ExecutionError::RegisterWindowMismatch);
    }

    let _ = registers.active_window_authority(request.caller_frame, request.caller_window)?;
    registers.validate_writable_register(request.caller_window, request.destination)?;

    Ok(ConstructReturnContinuation {
        caller_frame: request.caller_frame,
        caller_window: request.caller_window,
        callee_frame: None,
        owner: request.owner,
        construct_bytecode_index: request.construct_bytecode_index,
        resume_bytecode_index: request.resume_bytecode_index,
        destination: request.destination,
        argument_count_including_this: request.argument_count_including_this,
        callee_value: request.callee_value,
        callee_object: value_cell_payload(request.callee_value)
            .and_then(|payload| heap.cell_for_payload(payload))
            .map(ObjectId),
        constructor_this: request.constructor_this,
        post_return_field_initialization_constructors: request
            .post_return_field_initialization_constructors,
    })
}

pub(crate) fn validate_call_return_continuation(
    stack: &ExecutionContextStack,
    registers: &RegisterFile,
    continuation: &CallReturnContinuation,
) -> Result<RegisterWindow, ExecutionError> {
    let Some(frame) = stack.top_frame() else {
        return Err(ExecutionError::NoActiveFrame);
    };
    if frame.id != continuation.caller_frame {
        return Err(ExecutionError::FrameMismatch {
            expected: continuation.caller_frame,
            actual: Some(frame.id),
        });
    }
    if frame.code_block != Some(continuation.owner) {
        return Err(ExecutionError::CodeBlockMismatch {
            expected: continuation.owner,
            actual: frame.code_block,
        });
    }
    let window = frame.register_window;
    let _ = registers.active_window_authority(continuation.caller_frame, window)?;
    registers.validate_writable_register(window, continuation.destination)?;
    Ok(window)
}

pub(crate) fn validate_construct_return_continuation(
    stack: &ExecutionContextStack,
    registers: &RegisterFile,
    continuation: &ConstructReturnContinuation,
) -> Result<RegisterWindow, ExecutionError> {
    let Some(frame) = stack.top_frame() else {
        return Err(ExecutionError::NoActiveFrame);
    };
    if frame.id != continuation.caller_frame {
        return Err(ExecutionError::FrameMismatch {
            expected: continuation.caller_frame,
            actual: Some(frame.id),
        });
    }
    if frame.code_block != Some(continuation.owner) {
        return Err(ExecutionError::CodeBlockMismatch {
            expected: continuation.owner,
            actual: frame.code_block,
        });
    }
    if frame.register_window != continuation.caller_window {
        return Err(ExecutionError::RegisterWindowMismatch);
    }
    let _ =
        registers.active_window_authority(continuation.caller_frame, continuation.caller_window)?;
    registers.validate_writable_register(continuation.caller_window, continuation.destination)?;
    Ok(continuation.caller_window)
}

pub(crate) fn pop_call_return_callee(
    state: &mut DispatchState<'_>,
    continuation: CallReturnContinuation,
) -> Result<InstalledCallFrame, ExecutionError> {
    let callee = continuation
        .callee_frame
        .ok_or(ExecutionError::InvalidCallContinuation)?;
    let actual = state.stack.top_frame().map(|frame| frame.id);
    if actual != Some(callee) {
        return Err(ExecutionError::FrameMismatch {
            expected: callee,
            actual,
        });
    }
    if state
        .stack
        .top_frame()
        .and_then(|frame| frame.return_continuation)
        != Some(continuation)
    {
        return Err(ExecutionError::InvalidCallContinuation);
    }
    let frame = state.stack.pop_frame(state.registers, callee)?;
    Ok(frame)
}

pub(crate) fn discard_call_return_callee_if_present(
    state: &mut DispatchState<'_>,
    continuation: CallReturnContinuation,
) -> Result<(), ExecutionError> {
    let Some(callee) = continuation.callee_frame else {
        return Err(ExecutionError::InvalidCallContinuation);
    };
    if state.stack.frame(callee).is_none() {
        return Ok(());
    }
    pop_call_return_callee(state, continuation).map(|_| ())
}

pub(crate) fn finish_ordinary_js_call_return(
    state: &mut DispatchState<'_>,
    continuation: CallReturnContinuation,
    completion: ExecutionCompletion,
) -> DispatchOutcome {
    match completion {
        ExecutionCompletion::Returned(value) => {
            if let Err(error) = pop_call_return_callee(state, continuation) {
                return DispatchOutcome::Fail(error);
            }
            let caller_window = match validate_call_return_continuation(
                state.stack,
                state.registers,
                &continuation,
            ) {
                Ok(window) => window,
                Err(error) => return DispatchOutcome::Fail(error),
            };
            match state
                .registers
                .write(caller_window, continuation.destination, value)
            {
                Ok(()) => DispatchOutcome::ContinueTo(continuation.resume_bytecode_index),
                Err(error) => DispatchOutcome::Fail(error),
            }
        }
        ExecutionCompletion::Threw(pending) => {
            if let Err(error) = discard_call_return_callee_if_present(state, continuation) {
                return DispatchOutcome::Fail(error);
            }
            DispatchOutcome::Throw(pending.value)
        }
        ExecutionCompletion::Failed(error) => {
            if let Err(cleanup_error) = discard_call_return_callee_if_present(state, continuation) {
                return DispatchOutcome::Fail(cleanup_error);
            }
            DispatchOutcome::Fail(error)
        }
        ExecutionCompletion::OrdinaryBytecodeCall(_)
        | ExecutionCompletion::OrdinaryBytecodeConstruct(_)
        | ExecutionCompletion::BaselineLoopHandoff(_)
        | ExecutionCompletion::FunctionValueCall(_)
        | ExecutionCompletion::EvalRequest(_)
        | ExecutionCompletion::CompileFunctionRequest(_)
        | ExecutionCompletion::Terminated(_)
        | ExecutionCompletion::Suspended(_) => {
            if let Err(error) = discard_call_return_callee_if_present(state, continuation) {
                return DispatchOutcome::Fail(error);
            }
            DispatchOutcome::Fail(ExecutionError::InvalidCallCompletion)
        }
    }
}

