pub enum RegisterSlotKind {
    Local,
    Argument,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct RegisterRootDescriptor {
    pub root: RootRecord,
    pub frame: CallFrameId,
    pub slot: usize,
    pub slot_kind: RegisterSlotKind,
    pub value: RuntimeValue,
    pub cell_payload: Option<usize>,
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct ExecutionRootSnapshot {
    pub frame_roots: Vec<FrameRootDescriptor>,
    pub register_roots: Vec<RegisterRootDescriptor>,
}

impl ExecutionRootSnapshot {
    pub fn precise_root_records(&self) -> Vec<RootRecord> {
        self.frame_roots
            .iter()
            .map(|descriptor| descriptor.root)
            .chain(self.register_roots.iter().map(|descriptor| descriptor.root))
            .collect()
    }
}

fn frame_local_capacity(shape: RegisterFrameShape) -> u32 {
    shape
        .num_callee_locals
        .max(shape.num_vars.saturating_add(shape.num_temporaries))
}

fn empty_value() -> RuntimeValue {
    RuntimeValue::from_encoded(EncodedJsValue(0))
}

fn is_empty_value(value: RuntimeValue) -> bool {
    value.is_empty_or_deleted_sentinel()
}

fn read_constant(
    constants: Option<&LinkedConstantPool>,
    index: u32,
) -> Result<RuntimeValue, ExecutionError> {
    let constants = constants.ok_or(ExecutionError::MissingConstantPool)?;
    let index = usize::try_from(index).map_err(|_| ExecutionError::RegisterOutOfBounds)?;
    match constants
        .constants
        .get(index)
        .map(|constant| constant.value)
    {
        Some(ConstantValue::Encoded(value)) => Ok(value),
        Some(_) => Err(ExecutionError::DeferredConstant),
        None => Err(ExecutionError::RegisterOutOfBounds),
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct RegisterWindow {
    pub owner: CallFrameId,
    pub base: usize,
    pub local_count: usize,
    pub argument_base: usize,
    pub argument_count: usize,
    pub this_offset: ThisArgumentOffset,
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub enum ExecutionError {
    NoActiveEntry,
    NoActiveFrame,
    EntryMismatch {
        expected: EntryFrameId,
        actual: Option<EntryFrameId>,
    },
    FrameMismatch {
        expected: CallFrameId,
        actual: Option<CallFrameId>,
    },
    CodeBlockMismatch {
        expected: CodeBlockId,
        actual: Option<CodeBlockId>,
    },
    InvalidArgumentCount,
    RegisterCapacityExceeded,
    RegisterOutOfBounds,
    RegisterWindowMismatch,
    InvalidRegister,
    CannotWriteConstant,
    CannotAddressHeaderAsValue,
    MissingConstantPool,
    DeferredConstant,
    EmptyInstructionStream,
    InvalidBytecodeIndex(BytecodeIndex),
    BytecodeDecode(InstructionDecodeError),
    DispatchStepLimitExceeded,
    UnsupportedOpcode(Opcode),
    OperandAccess(OperandAccessError),
    ExpectedInt32,
    Int32ArithmeticOverflow,
    ExpectedObject,
    ExpectedArrayIndex,
    ExpectedFunction,
    ExpectedPropertyKey,
    MissingSuperBinding,
    MissingStringLiteral(u32),
    MissingIdentifierText(u32),
    MissingPendingException,
    MissingCapture(u32),
    GlobalLexicalBindingNotFound(String),
    GlobalLexicalTemporalDeadZone(String),
    GlobalLexicalReadOnly(String),
    GlobalLexicalAlreadyInitialized(String),
    GlobalLexicalDeleted(String),
    GlobalLexicalDuplicateBinding(String),
    UnknownObject,
    MissingFunctionCode(u32),
    InvalidCallCompletion,
    InvalidCallContinuation,
    UnknownHostGlobal,
    HostReadFile,
    BarrierDecision(BarrierDecisionError),
    MissingStaticCellMetadata(CellType),
    HeapIntegration(HeapIntegrationError),
    RootSetSemantic(RootSetSemanticError),
    UnresolvedRegisterRoot {
        slot: usize,
    },
    BaselineGeneratedCodeUnavailable,
    BaselineGeneratedExecutionRejected,
    GcBoundaryViolation,
    // C++ JSC divergence (first cut): globalFuncEval throws a JS SyntaxError when
    // the eval source fails to parse/compile (IndirectEvalExecutable::tryCreate
    // returns null with an exception, JSGlobalObjectFunctions.cpp:517-520). The
    // Vm-owned eval compile here surfaces a parse/compile failure as a Vm-level
    // error instead of allocating a thrown SyntaxError object. Follow-up: turn
    // this into a thrown SyntaxError at the eval call site.
    EvalCompilationFailed,
}

impl From<BarrierDecisionError> for ExecutionError {
    fn from(error: BarrierDecisionError) -> Self {
        Self::BarrierDecision(error)
    }
}

impl From<HeapIntegrationError> for ExecutionError {
    fn from(error: HeapIntegrationError) -> Self {
        Self::HeapIntegration(error)
    }
}

impl From<RootSetSemanticError> for ExecutionError {
    fn from(error: RootSetSemanticError) -> Self {
        Self::RootSetSemantic(error)
    }
}

