    /// op_call slow-path funnel — the UNLINKED VIRTUAL CALL (JSC's
    /// `operationVirtualCall` / the unlinked `virtualThunk` path, jit/CallLinkInfo +
    /// jit/ThunkGenerators.cpp `virtualThunkFor`): every baseline call site starts
    /// UNLINKED and routes the callee value through the faithful generic dispatch.
    /// `execute_function_value` IS that dispatch — it resolves the callee value
    /// (proxy / bound-function / native / bytecode), runs `this` normalization +
    /// arity fill, pushes the callee frame into the LIVE register arena, and runs the
    /// callee to completion — exactly the work the interpreter's `dispatch_call`
    /// performs, minus the caller-window/instruction plumbing (the boxed
    /// `callee`/`this`/`arguments` arrive already decoded from the JIT caller's
    /// frame). `this` is `undefined` (op_call's implicit receiver,
    /// `CallObservationThisSource::ImplicitUndefined`).
    ///
    /// DIVERGENCE (B5-first-cut, also documented at the emitter + the
    /// `Vm::operation_call` wrapper): the callee runs through its INTERPRETER entry
    /// here — it does NOT tier-up-from-the-JIT-caller and there is no emitted native
    /// direct-link / bl-chain / arity stub yet. That native call linking is the
    /// deferred B5-full perf follow-up; this first cut establishes the CORRECT call
    /// semantics (faithful to an unlinked site whose first execution enters the
    /// callee through its lower tier).
    pub(crate) fn jit_call_function_value(
        &mut self,
        state: &mut DispatchState<'_>,
        callee: RuntimeValue,
        this_value: RuntimeValue,
        arguments: &[RuntimeValue],
    ) -> Result<RuntimeValue, DispatchOutcome> {
        self.execute_function_value(state, callee, this_value, arguments)
    }

    fn get_property_value_with_completion(
        &mut self,
        state: &mut DispatchState<'_>,
        object: RuntimeValue,
        key: &CorePropertyKey,
        receiver: RuntimeValue,
        completion_context: Option<FunctionValuePropertyOperationContext>,
    ) -> Result<RuntimeValue, DispatchOutcome> {
        let lookup_site = self.pending_property_lookup_site.take();
        if self.objects.is_proxy(object) {
            let record = lookup_site.map(|site| {
                CorePropertyLookupRecord::opaque(
                    site,
                    object,
                    self.objects.find(object).map(|_| object),
                    key,
                    true,
                    PropertyCacheability::TaintedByOpaqueObject,
                )
            });
            let result = self.get_proxy_property_value_with_completion(
                state,
                object,
                key,
                receiver,
                completion_context,
                record.clone(),
            );
            if let Some(record) = record {
                if !matches!(result, Err(DispatchOutcome::FunctionValueCall(_))) {
                    self.record_property_lookup(record);
                }
            }
            return result;
        }
        if self.symbols.is_symbol(object) {
            let record = lookup_site.map(|site| {
                CorePropertyLookupRecord::opaque(
                    site,
                    object,
                    None,
                    key,
                    true,
                    PropertyCacheability::Disallowed,
                )
            });
            let result = self.get_symbol_property_value_with_completion(
                state,
                object,
                key,
                receiver,
                completion_context,
                record.clone(),
            );
            if let Some(record) = record {
                if !matches!(result, Err(DispatchOutcome::FunctionValueCall(_))) {
                    self.record_property_lookup(record);
                }
            }
            return result;
        }
        if self.bigints.is_bigint(object) {
            let record = lookup_site.map(|site| {
                CorePropertyLookupRecord::opaque(
                    site,
                    object,
                    None,
                    key,
                    true,
                    PropertyCacheability::Disallowed,
                )
            });
            let result = self.get_bigint_property_value_with_completion(
                state,
                object,
                key,
                receiver,
                completion_context,
                record.clone(),
            );
            if let Some(record) = record {
                if !matches!(result, Err(DispatchOutcome::FunctionValueCall(_))) {
                    self.record_property_lookup(record);
                }
            }
            return result;
        }
        if self.strings.text(object).is_some() {
            return self.get_string_property_value_with_completion(
                state,
                object,
                key,
                receiver,
                completion_context,
                lookup_site,
            );
        }
        // C++ JSC: toThisNumber / Number autoboxing — primitive numbers route
        // through Number.prototype for property access (e.g. (42).toString()).
        if object.as_number().is_some() {
            let record = lookup_site.map(|site| {
                CorePropertyLookupRecord::opaque(
                    site,
                    object,
                    None,
                    key,
                    true,
                    PropertyCacheability::Disallowed,
                )
            });
            let result = self.get_number_property_value_with_completion(
                state,
                object,
                key,
                receiver,
                completion_context,
                record.clone(),
            );
            if let Some(record) = record {
                if !matches!(result, Err(DispatchOutcome::FunctionValueCall(_))) {
                    self.record_property_lookup(record);
                }
            }
            return result;
        }
        // C++ JSC: Boolean autoboxing — primitive booleans route through
        // Boolean.prototype for property access.
        if object.as_bool().is_some() {
            let record = lookup_site.map(|site| {
                CorePropertyLookupRecord::opaque(
                    site,
                    object,
                    None,
                    key,
                    true,
                    PropertyCacheability::Disallowed,
                )
            });
            let result = self.get_boolean_property_value_with_completion(
                state,
                object,
                key,
                receiver,
                completion_context,
                record.clone(),
            );
            if let Some(record) = record {
                if !matches!(result, Err(DispatchOutcome::FunctionValueCall(_))) {
                    self.record_property_lookup(record);
                }
            }
            return result;
        }

        // C++ JSC get_by_id / get_by_val slow path: the base goes through
        // JSValue::toObject (LLIntSlowPaths.cpp:1212; CommonSlowPaths) which, for an
        // undefined or null base, calls toObjectSlowCase -> createNotAnObjectError
        // (JSCJSValue.cpp:154, ExceptionHelpers.cpp:318) and throws a catchable
        // TypeError. Cells/primitives are handled by the typed branches above; only
        // undefined/null reach here as a JS-observable "x is not an object" throw.
        // (The objects.get_property fallthrough below would otherwise surface this
        // as a fatal ExpectedObject failure, swallowing the catch.)
        if matches!(object.kind(), ValueKind::Undefined | ValueKind::Null) {
            return Err(self.not_an_object_type_error(state.heap, object));
        }
        let (property, record) = match lookup_site {
            Some(site) => {
                let (property, record) = self
                    .objects
                    .get_property_with_lookup_record(object, key, site)
                    .map_err(DispatchOutcome::Fail)?;
                (property, Some(record))
            }
            None => (
                self.objects
                    .get_property(object, key)
                    .map_err(DispatchOutcome::Fail)?,
                None,
            ),
        };
        match property {
            CorePropertyGet::Data(value) => {
                if let Some(record) = record {
                    self.record_property_lookup(record);
                }
                Ok(value)
            }
            CorePropertyGet::Getter(getter) => {
                let completion = completion_context.map(|context| {
                    context.completion(
                        record
                            .clone()
                            .map(FunctionValuePropertyObservation::property_load)
                            .unwrap_or_else(FunctionValuePropertyObservation::none),
                    )
                });
                let result = self.execute_function_value_with_completion(
                    state,
                    getter,
                    receiver,
                    &[],
                    completion,
                );
                if let Some(record) = record {
                    if !matches!(result, Err(DispatchOutcome::FunctionValueCall(_))) {
                        self.record_property_lookup(record);
                    }
                }
                result
            }
            CorePropertyGet::Missing => {
                if let Some(record) = record {
                    self.record_property_lookup(record);
                }
                Ok(RuntimeValue::undefined())
            }
            CorePropertyGet::AccessorWithoutGetter => {
                if let Some(record) = record {
                    self.record_property_lookup(record);
                }
                Ok(RuntimeValue::undefined())
            }
        }
    }

    fn get_proxy_property_value_with_completion(
        &mut self,
        state: &mut DispatchState<'_>,
        proxy: RuntimeValue,
        key: &CorePropertyKey,
        receiver: RuntimeValue,
        completion_context: Option<FunctionValuePropertyOperationContext>,
        load_record: Option<CorePropertyLookupRecord>,
    ) -> Result<RuntimeValue, DispatchOutcome> {
        let (target, handler) = self.proxy_target_handler_or_throw(state.heap, proxy)?;
        let Some(trap) = self.proxy_trap(state, handler, "get")? else {
            let completion_context = FunctionValuePropertyCallCompletion::with_observation(
                completion_context,
                load_record
                    .map(FunctionValuePropertyObservation::property_load)
                    .unwrap_or_else(FunctionValuePropertyObservation::none),
            )
            .into_context();
            return self.get_property_value_with_completion(
                state,
                target,
                key,
                receiver,
                completion_context,
            );
        };
        let key_value = self
            .property_key_value(state.heap, key)
            .map_err(DispatchOutcome::Fail)?;
        let completion = completion_context.map(|context| {
            context.completion(
                load_record
                    .map(FunctionValuePropertyObservation::property_load)
                    .unwrap_or_else(FunctionValuePropertyObservation::none),
            )
        });
        self.execute_function_value_with_completion(
            state,
            trap,
            handler,
            &[target, key_value, receiver],
            completion,
        )
    }

    fn get_symbol_property_value_with_completion(
        &mut self,
        state: &mut DispatchState<'_>,
        value: RuntimeValue,
        key: &CorePropertyKey,
        receiver: RuntimeValue,
        completion_context: Option<FunctionValuePropertyOperationContext>,
        load_record: Option<CorePropertyLookupRecord>,
    ) -> Result<RuntimeValue, DispatchOutcome> {
        if !self.symbols.is_symbol(value) {
            return Err(DispatchOutcome::Fail(ExecutionError::ExpectedObject));
        }
        match self
            .objects
            .get_symbol_prototype_property(key)
            .map_err(DispatchOutcome::Fail)?
        {
            CorePropertyGet::Data(value) => Ok(value),
            CorePropertyGet::Getter(getter) => {
                let completion = completion_context.map(|context| {
                    context.completion(
                        load_record
                            .map(FunctionValuePropertyObservation::property_load)
                            .unwrap_or_else(FunctionValuePropertyObservation::none),
                    )
                });
                self.execute_function_value_with_completion(
                    state,
                    getter,
                    receiver,
                    &[],
                    completion,
                )
            }
            CorePropertyGet::Missing | CorePropertyGet::AccessorWithoutGetter => {
                Ok(RuntimeValue::undefined())
            }
        }
    }

