/// Resolves the active interpreter frame for a generated baseline body.
///
/// This is only a local frame/register boundary check. It does not enter,
/// resume, or finish an interpreter dispatch run, so callers that execute
/// bytecode must still use the existing execution boundary for root cleanup.
pub(crate) fn baseline_active_frame(
    stack: &ExecutionContextStack,
    expected_frame: CallFrameId,
    expected_code_block: CodeBlockId,
) -> Result<(InstalledCallFrame, RegisterWindow), ExecutionError> {
    let Some(frame) = stack.top_frame().cloned() else {
        return Err(ExecutionError::NoActiveFrame);
    };
    if frame.id != expected_frame {
        return Err(ExecutionError::FrameMismatch {
            expected: expected_frame,
            actual: Some(frame.id),
        });
    }
    if frame.code_block != Some(expected_code_block) {
        return Err(ExecutionError::CodeBlockMismatch {
            expected: expected_code_block,
            actual: frame.code_block,
        });
    }
    let window = frame.register_window;
    Ok((frame, window))
}

#[allow(dead_code)]
pub(crate) fn baseline_read_register(
    registers: &RegisterFile,
    code_block: &CodeBlock,
    window: RegisterWindow,
    register: VirtualRegister,
) -> Result<RuntimeValue, ExecutionError> {
    registers
        .active_window_authority(window.owner, window)?
        .read(register, Some(code_block.constants()))
}

#[allow(dead_code)]
pub(crate) fn baseline_write_register(
    registers: &mut RegisterFile,
    window: RegisterWindow,
    register: VirtualRegister,
    value: RuntimeValue,
) -> Result<(), ExecutionError> {
    registers
        .active_window_authority_mut(window.owner, window)?
        .write(register, value)
}

#[allow(dead_code)]
pub(crate) fn baseline_return_register(
    registers: &RegisterFile,
    code_block: &CodeBlock,
    window: RegisterWindow,
    register: VirtualRegister,
) -> Result<RuntimeValue, ExecutionError> {
    baseline_read_register(registers, code_block, window, register)
}

