    #[test]
    fn put_by_id_megamorphic_property_name_gate_matches_jsc_exclusions() {
        for name in [
            "field",
            "toString",
            "constructor",
            "length",
            "name",
            "prototype",
        ] {
            assert!(can_use_put_by_id_megamorphic_property_name(name));
        }
        for name in ["__proto__", "0", "42"] {
            assert!(!can_use_put_by_id_megamorphic_property_name(name));
        }
        assert!(can_use_put_by_id_megamorphic_property_name("01"));
        assert!(can_use_put_by_id_megamorphic_property_name("4294967295"));
    }

    struct CountingHost {
        count: usize,
        return_at: usize,
        return_value: RuntimeValue,
    }

    impl DispatchHost for CountingHost {
        fn dispatch_instruction(
            &mut self,
            _state: &mut DispatchState<'_>,
            _instruction: DispatchInstruction<'_>,
        ) -> DispatchOutcome {
            self.count = self.count.saturating_add(1);
            if self.count == self.return_at {
                DispatchOutcome::Return(self.return_value)
            } else {
                DispatchOutcome::Continue
            }
        }
    }

    fn code_block(instructions: Vec<TypedInstruction>) -> CodeBlock {
        code_block_with_frame(
            instructions,
            RegisterFrameShape {
                num_parameters_including_this: 1,
                num_vars: 1,
                num_callee_locals: 0,
                num_temporaries: 1,
                special: Default::default(),
            },
        )
    }

    fn code_block_with_frame(
        instructions: Vec<TypedInstruction>,
        shape: RegisterFrameShape,
    ) -> CodeBlock {
        let stream = PackedInstructionStream::from_typed_placeholder(instructions);
        let unlinked = UnlinkedCodeBlock::new(CodeKind::Program, stream).with_frame(shape);
        CodeBlock::from_unlinked(unlinked, LinkContext::default())
    }

    fn raw_code_block_with_constants(bytes: Vec<u8>, constants: UnlinkedConstantPool) -> CodeBlock {
        let stream = PackedInstructionStream::from_raw_packed_bytes(bytes);
        let unlinked = UnlinkedCodeBlock::new(CodeKind::Program, stream)
            .with_frame(RegisterFrameShape {
                num_parameters_including_this: 1,
                num_vars: 1,
                num_callee_locals: 0,
                num_temporaries: 1,
                special: Default::default(),
            })
            .with_constants(constants);
        CodeBlock::from_unlinked(unlinked, LinkContext::default())
    }

    fn code_block_with_string_literals(
        instructions: Vec<TypedInstruction>,
        literals: Vec<(u32, String)>,
    ) -> CodeBlock {
        let stream = PackedInstructionStream::from_typed_placeholder(instructions);
        let unlinked = UnlinkedCodeBlock::new(CodeKind::Program, stream)
            .with_frame(RegisterFrameShape {
                num_parameters_including_this: 1,
                num_vars: 1,
                num_callee_locals: 0,
                num_temporaries: 1,
                special: Default::default(),
            })
            .with_string_literals(literals);
        CodeBlock::from_unlinked(unlinked, LinkContext::default())
    }

    fn typed(offset: u32) -> TypedInstruction {
        TypedInstruction {
            opcode: Opcode::Reserved,
            width: crate::bytecode::opcode::OperandWidth::Narrow,
            operands: Vec::new(),
            schema: None,
            bytecode_index: Some(BytecodeIndex::from_offset(offset)),
        }
    }

    fn core_typed(offset: u32, opcode: CoreOpcode, operands: Vec<Operand>) -> TypedInstruction {
        TypedInstruction {
            opcode: opcode.opcode(),
            width: crate::bytecode::opcode::OperandWidth::Narrow,
            operands,
            schema: None,
            bytecode_index: Some(BytecodeIndex::from_offset(offset)),
        }
    }

    fn local(index: u32) -> VirtualRegister {
        VirtualRegister::local(index)
    }

    fn argument_including_this(index: u32) -> VirtualRegister {
        VirtualRegister::argument_including_this(
            index,
            CallFrameSlotLayout::JSC_RUST.this_argument_offset,
        )
    }

    fn function_code_block_with_parameters(
        instructions: Vec<TypedInstruction>,
        parameters_including_this: u32,
    ) -> CodeBlock {
        code_block_with_frame(
            instructions,
            RegisterFrameShape {
                num_parameters_including_this: parameters_including_this,
                num_vars: 4,
                num_callee_locals: 0,
                num_temporaries: 0,
                special: Default::default(),
            },
        )
    }

    fn enter_program_frame(
        stack: &mut ExecutionContextStack,
        registers: &mut RegisterFile,
        code_block_id: CodeBlockId,
        block: &CodeBlock,
        argument_values: Vec<RuntimeValue>,
    ) {
        stack.enter(ExecutionEntryRecord::Program(ProgramExecutionEntry {
            code_block: code_block_id,
            global_object: GlobalObjectId(ObjectId(CellId(1))),
            this_value: RuntimeValue::undefined(),
        }));
        stack
            .push_frame(
                registers,
                FramePushRequest {
                    code_block: Some(code_block_id),
                    callee: None,
                    callee_value: None,
                    lexical_scope: None,
                    shape: block.unlinked().frame(),
                    argument_count_including_this: argument_values.len().max(1) as u32,
                    argument_values,
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
                None,
            )
            .unwrap();
    }

    #[derive(Clone, Debug, Eq, PartialEq)]
    struct TargetedRootSyncObservation {
        existing: Vec<TargetedRootRecord>,
        desired: Vec<TargetedRootRecord>,
    }

    #[derive(Default)]
    struct ObservingCoreHost {
        core: CoreOpcodeDispatchHost,
        observations: Vec<TargetedRootSyncObservation>,
    }

    impl ObservingCoreHost {
        fn new() -> Self {
            Self::default()
        }
    }

    impl DispatchHost for ObservingCoreHost {
        fn targeted_register_roots(
            &mut self,
            heap: &mut Heap,
            snapshot: &ExecutionRootSnapshot,
        ) -> Result<Vec<TargetedRootRecord>, ExecutionError> {
            let existing = heap.targeted_roots().records().to_vec();
            let desired = self.core.targeted_register_roots(heap, snapshot)?;
            self.observations.push(TargetedRootSyncObservation {
                existing,
                desired: desired.clone(),
            });
            Ok(desired)
        }

        fn dispatch_instruction(
            &mut self,
            state: &mut DispatchState<'_>,
            instruction: DispatchInstruction<'_>,
        ) -> DispatchOutcome {
            self.core.dispatch_instruction(state, instruction)
        }
    }

    #[derive(Clone, Debug, Eq, PartialEq)]
    struct JsCallFrameSnapshot {
        frame: CallFrameId,
        caller: Option<CallFrameId>,
        continuation: Option<CallReturnContinuation>,
        arguments: Vec<RuntimeValue>,
    }

    struct RecordingCallFrameHost {
        core: CoreOpcodeDispatchHost,
        snapshots: Vec<JsCallFrameSnapshot>,
    }

    impl RecordingCallFrameHost {
        fn new(function_blocks: Vec<CodeBlock>) -> Self {
            Self {
                core: CoreOpcodeDispatchHost::with_function_blocks(function_blocks),
                snapshots: Vec::new(),
            }
        }
    }

    impl DispatchHost for RecordingCallFrameHost {
        fn dispatch_instruction(
            &mut self,
            state: &mut DispatchState<'_>,
            instruction: DispatchInstruction<'_>,
        ) -> DispatchOutcome {
            if let Some(frame) = state.stack.top_frame() {
                if frame.caller.is_some()
                    && !self
                        .snapshots
                        .iter()
                        .any(|snapshot| snapshot.frame == frame.id)
                {
                    let arguments = (0..frame.argument_count_including_this)
                        .map(|index| {
                            state
                                .registers
                                .read(
                                    frame.register_window,
                                    argument_including_this(index),
                                    Some(state.code_block.constants()),
                                )
                                .unwrap()
                        })
                        .collect();
                    self.snapshots.push(JsCallFrameSnapshot {
                        frame: frame.id,
                        caller: frame.caller,
                        continuation: frame.return_continuation,
                        arguments,
                    });
                }
            }
            let outcome = self.core.dispatch_instruction(state, instruction);
            self.snapshots = self
                .core
                .call_frame_snapshots_for_test
                .iter()
                .map(|snapshot| JsCallFrameSnapshot {
                    frame: snapshot.frame,
                    caller: snapshot.caller,
                    continuation: snapshot.continuation,
                    arguments: snapshot.arguments.clone(),
                })
                .collect();
            outcome
        }
    }

