    #[derive(Clone, Debug, Eq, PartialEq)]
    struct ObjectStoreMutationSnapshot {
        object_count: usize,
        next_structure_id: u32,
        structure_id: StructureId,
        properties: HashMap<CorePropertyKey, CoreProperty>,
        property_offsets: HashMap<CorePropertyKey, PropertyOffset>,
        next_property_offset: i32,
        property_order: Vec<CorePropertyKey>,
        elements: Vec<Option<RuntimeValue>>,
    }

    fn object_store_mutation_snapshot(
        objects: &CoreObjectStore,
        object: RuntimeValue,
    ) -> ObjectStoreMutationSnapshot {
        let cell = objects.find(object).expect("object cell");
        let structure_id = cell.structure_id;
        let elements = objects.butterfly_elements(cell.butterfly);
        // gc-r4 B-iv: the per-cell `properties` HashMap + `property_order` are gone; rebuild
        // the observable views from the cell's Structure (offset/attribute authority) +
        // butterfly (value authority), in PropertyTable entry order.
        let mut properties = HashMap::new();
        let mut property_offsets = HashMap::new();
        let mut property_order = Vec::new();
        for (key, offset, _attrs) in objects.structure_property_keys(structure_id) {
            if let Some(property) = objects.own_property_from_shape(cell, &key) {
                properties.insert(key.clone(), property);
            }
            property_offsets.insert(key.clone(), offset);
            property_order.push(key);
        }
        ObjectStoreMutationSnapshot {
            // gc-r4 R4a: the deleted `objects` Vec len is now the arena's monotone allocated
            // cell count (no sweep pre-R4b, so it tracks total live object cells like the Vec did).
            object_count: objects.space.allocated_blob_cell_count(),
            next_structure_id: objects.structure_table.peek_next_handle().raw(),
            structure_id,
            properties,
            property_offsets,
            next_property_offset: objects
                .next_property_offset_for_structure(structure_id)
                .raw(),
            property_order,
            elements,
        }
    }

