    #[test]
    fn generated_property_store_probe_rejects_malformed_plans_before_live_base_claims() {
        let mut host = CoreOpcodeDispatchHost::new();
        let object = host.objects.allocate_with_prototype(None);
        let key = CorePropertyKey::Identifier(11);
        host.objects
            .set_data_own(object, &key, RuntimeValue::from_i32(42))
            .unwrap();
        let plan = generated_property_store_replace_plan(
            object_structure_id(&host.objects, object),
            object_property_offset(&host.objects, object, &key).expect("offset"),
            11,
        );
        let snapshot = object_store_mutation_snapshot(&host.objects, object);
        let non_cell_base = RuntimeValue::from_i32(1);
        let stored_value = RuntimeValue::from_i32(99);

        let mut unsupported_kind = plan.clone();
        unsupported_kind.plan_kind = PropertyStoreAccessCasePlanKind::Unsupported;
        assert_eq!(
            store_probe_miss_reason(host.probe_generated_property_store(
                generated_property_store_probe_request(
                    &unsupported_kind,
                    non_cell_base,
                    stored_value,
                )
            )),
            GeneratedPropertyStoreProbeMissReason::UnsupportedPlan
        );

        let mut wrong_stub = plan.clone();
        wrong_stub.planned_stub_kind = InlineCacheStubKind::DataOnlyHandler;
        assert_eq!(
            store_probe_miss_reason(host.probe_generated_property_store(
                generated_property_store_probe_request(&wrong_stub, non_cell_base, stored_value)
            )),
            GeneratedPropertyStoreProbeMissReason::UnsupportedPlanMetadata
        );

        let mut dynamic_key = plan.clone();
        dynamic_key.key = CacheKey::Dynamic;
        dynamic_key.access_case.key = CacheKey::Dynamic;
        assert_eq!(
            store_probe_miss_reason(host.probe_generated_property_store(
                generated_property_store_probe_request(&dynamic_key, non_cell_base, stored_value)
            )),
            GeneratedPropertyStoreProbeMissReason::KeyNotRepresentable
        );

        let indexed_key = CacheKey::Property(PropertyKey::from_index(
            PropertyIndex::from_canonical_index(0),
        ));
        let mut indexed_plan = plan.clone();
        indexed_plan.key = indexed_key;
        indexed_plan.access_case.key = indexed_key;
        assert_eq!(
            store_probe_miss_reason(host.probe_generated_property_store(
                generated_property_store_probe_request(&indexed_plan, non_cell_base, stored_value)
            )),
            GeneratedPropertyStoreProbeMissReason::IndexedProperty
        );

        let mut missing_offset = plan.clone();
        missing_offset.access_case.offset = None;
        assert_eq!(
            store_probe_miss_reason(host.probe_generated_property_store(
                generated_property_store_probe_request(
                    &missing_offset,
                    non_cell_base,
                    stored_value
                )
            )),
            GeneratedPropertyStoreProbeMissReason::MissingOrInvalidOffset
        );

        let mut replace_transition = plan.clone();
        replace_transition.access_case.new_structure = Some(StructureId::new(300));
        assert_eq!(
            store_probe_miss_reason(host.probe_generated_property_store(
                generated_property_store_probe_request(
                    &replace_transition,
                    non_cell_base,
                    stored_value,
                )
            )),
            GeneratedPropertyStoreProbeMissReason::TransitionStructureMismatch
        );

        assert_eq!(
            snapshot,
            object_store_mutation_snapshot(&host.objects, object)
        );
    }

