    #[test]
    fn generated_property_store_mutation_replace_commits_existing_slot_with_one_barrier() {
        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let object = host.objects.allocate_with_prototype(None);
        let key = CorePropertyKey::Identifier(11);
        let original_value = RuntimeValue::from_i32(42);
        host.objects
            .set_data_own(object, &key, original_value)
            .unwrap();
        let stored_value = host.objects.allocate_with_prototype(None);
        let plan = generated_property_store_replace_plan(
            object_structure_id(&host.objects, object),
            object_property_offset(&host.objects, object, &key).expect("property offset"),
            11,
        );
        let hit = store_probe_hit(host.probe_generated_property_store(
            generated_property_store_probe_request(&plan, object, stored_value),
        ));
        let request = GeneratedPropertyStoreMutationRequest::new(object, hit);
        let before = object_store_mutation_snapshot(&host.objects, object);

        let commit =
            store_mutation_commit(host.commit_generated_property_store(&mut heap, request));

        assert_eq!(
            commit,
            GeneratedPropertyStoreMutationCommit::host_confirmed_for_request(&request)
        );
        let mut expected = before.clone();
        expected.properties.insert(
            key.clone(),
            CoreProperty {
                kind: CorePropertyKind::Data(stored_value),
                attributes: CorePropertyAttributes::DATA_DEFAULT,
            },
        );
        assert_eq!(
            expected,
            object_store_mutation_snapshot(&host.objects, object)
        );
        assert_eq!(
            host.objects
                .get_own_property(object, &key)
                .unwrap()
                .expect("stored property")
                .kind,
            CorePropertyKind::Data(stored_value)
        );
        assert_single_value_store_barrier(
            &heap,
            BarrierRequirementOutcome::NotRequired(BarrierNotRequiredReason::TargetAlreadyVisible),
        );
    }

    #[test]
    fn generated_property_store_mutation_transition_commits_planned_structure_and_offset() {
        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let object = host.objects.allocate_with_prototype(None);
        let existing_key = CorePropertyKey::Identifier(10);
        let key = CorePropertyKey::Identifier(11);
        host.objects
            .set_data_own(object, &existing_key, RuntimeValue::from_i32(7))
            .unwrap();
        let stored_value = host.objects.allocate_with_prototype(None);
        // Fabricate the planned transition from a REAL add-property transition so the
        // planned structure actually maps `key` -> planned_offset in its PropertyTable
        // (the offset authority); the commit then stamps that real successor.
        let old_structure = object_structure_id(&host.objects, object);
        let (planned_new_structure, planned_offset) = host.objects.structure_add_property(
            old_structure,
            &key,
            CorePropertyAttributes::DATA_DEFAULT,
            false,
        );
        let plan = generated_property_store_transition_plan(
            object_structure_id(&host.objects, object),
            planned_offset,
            planned_new_structure,
            11,
        );
        let hit = store_probe_hit(host.probe_generated_property_store(
            generated_property_store_probe_request(&plan, object, stored_value),
        ));
        let request = GeneratedPropertyStoreMutationRequest::new(object, hit);
        let before = object_store_mutation_snapshot(&host.objects, object);

        let commit =
            store_mutation_commit(host.commit_generated_property_store(&mut heap, request));

        assert_eq!(
            commit,
            GeneratedPropertyStoreMutationCommit::host_confirmed_for_request(&request)
        );
        let mut expected = before.clone();
        expected.structure_id = planned_new_structure;
        expected.properties.insert(
            key.clone(),
            CoreProperty {
                kind: CorePropertyKind::Data(stored_value),
                attributes: CorePropertyAttributes::DATA_DEFAULT,
            },
        );
        expected
            .property_offsets
            .insert(key.clone(), planned_offset);
        expected.next_property_offset = expected
            .next_property_offset
            .checked_add(1)
            .expect("next offset");
        expected.property_order.push(key.clone());
        assert_eq!(
            expected,
            object_store_mutation_snapshot(&host.objects, object)
        );
        assert_eq!(
            object_structure_id(&host.objects, object),
            planned_new_structure
        );
        assert_eq!(
            object_property_offset(&host.objects, object, &key),
            Some(planned_offset)
        );
        assert_single_value_store_barrier(
            &heap,
            BarrierRequirementOutcome::NotRequired(BarrierNotRequiredReason::TargetAlreadyVisible),
        );
    }

    #[test]
    fn offset_indexed_read_matches_hashmap_across_structure_transition() {
        // Batch 2: the offset-indexed read of out_of_line_storage (the batch-3
        // machine-code `mov reg <- [base + offset*8]` analog, JSObject::getDirect)
        // must return exactly the authoritative HashMap value for a multi-property
        // object, including after a structure transition adds a later property.
        let mut host = CoreOpcodeDispatchHost::new();
        let object = host.objects.allocate_with_prototype(None);

        let key_a = CorePropertyKey::Identifier(100);
        let key_b = CorePropertyKey::Identifier(101);
        let key_c = CorePropertyKey::Identifier(102);
        let value_a = RuntimeValue::from_i32(11);
        let value_b = RuntimeValue::from_i32(22);
        let value_c = RuntimeValue::from_i32(33);

        host.objects.set_data_own(object, &key_a, value_a).unwrap();
        host.objects.set_data_own(object, &key_b, value_b).unwrap();
        let structure_before = object_structure_id(&host.objects, object);

        // Helper: read a key via the offset-indexed Vec path and assert it equals the
        // shape-reconstructed authoritative value (gc-r4 B-iv: the HashMap is gone; the
        // Structure+butterfly is the value authority via own_property_from_shape).
        let assert_offset_read_matches_hashmap =
            |objects: &CoreObjectStore, key: &CorePropertyKey, identifier: u32| {
                let cell = objects.find(object).expect("object cell");
                let offset = objects
                    .property_offset(object, key)
                    .expect("named data offset");
                let offset_value = generated_property_load_cell_data_property_at_offset(
                    objects,
                    cell,
                    GeneratedPropertyLoadCoreKey::Identifier(identifier),
                    offset,
                );
                let CorePropertyKind::Data(shape_value) = objects
                    .own_property_from_shape(cell, key)
                    .expect("shape property")
                    .kind
                else {
                    panic!("expected data property in the shape authority");
                };
                assert_eq!(
                    offset_value,
                    Some(shape_value),
                    "offset-indexed read must equal the shape value"
                );
            };

        // Both pre-transition properties read identically through the offset path.
        assert_offset_read_matches_hashmap(&host.objects, &key_a, 100);
        assert_offset_read_matches_hashmap(&host.objects, &key_b, 101);

        // Structure transition: adding key_c changes the structure id (new shape).
        host.objects.set_data_own(object, &key_c, value_c).unwrap();
        let structure_after = object_structure_id(&host.objects, object);
        assert_ne!(
            structure_before, structure_after,
            "adding a property must transition the structure id"
        );

        // After the transition every data property still reads identically, and the
        // newly added one resolves through the offset path too.
        assert_offset_read_matches_hashmap(&host.objects, &key_a, 100);
        assert_offset_read_matches_hashmap(&host.objects, &key_b, 101);
        assert_offset_read_matches_hashmap(&host.objects, &key_c, 102);

        // An in-place value update of an existing property is reflected by the offset
        // read (putDirectOffset lockstep on the DataOnlyReplace-style path).
        let updated_a = RuntimeValue::from_i32(99);
        host.objects
            .set_data_own(object, &key_a, updated_a)
            .unwrap();
        let cell = host.objects.find(object).expect("object cell");
        let offset_a = host
            .objects
            .property_offset(object, &key_a)
            .expect("named data offset");
        assert_eq!(
            generated_property_load_cell_data_property_at_offset(
                &host.objects,
                cell,
                GeneratedPropertyLoadCoreKey::Identifier(100),
                offset_a,
            ),
            Some(updated_a),
        );
    }

    #[test]
    fn offset_indexed_read_no_aliasing_across_64_property_boundary() {
        // gc-r4 Batch 2: with INLINE_CAPACITY == 6 the structure assigns offsets 0..5
        // (inline band) then jumps the 7th property to firstOutOfLineOffset == 64,65,...
        // (out-of-line band); offset_storage_index packs both bands into one contiguous
        // forward Vec (indices 0..N-1). Add >6 distinct data properties crossing the
        // 6->64 boundary and assert each reads back its OWN value via the offset path
        // (a wrong storage index would alias one property's slot onto another's).
        let mut host = CoreOpcodeDispatchHost::new();
        let object = host.objects.allocate_with_prototype(None);

        const N: u32 = 70; // well past the 6-property inline band / 64 jump
        for i in 0..N {
            let key = CorePropertyKey::Identifier(1000 + i);
            host.objects
                .set_data_own(object, &key, RuntimeValue::from_i32(i as i32))
                .unwrap();
        }

        for i in 0..N {
            let key = CorePropertyKey::Identifier(1000 + i);
            let cell = host.objects.find(object).expect("object cell");
            let offset = host
                .objects
                .property_offset(object, &key)
                .expect("named data offset");
            assert_eq!(
                generated_property_load_cell_data_property_at_offset(
                    &host.objects,
                    cell,
                    GeneratedPropertyLoadCoreKey::Identifier(1000 + i),
                    offset,
                ),
                Some(RuntimeValue::from_i32(i as i32)),
                "property {i} must read its own value, not an aliased slot"
            );
        }
    }

    // gc-r4 Batch 2: the structure's PropertyTable is the single offset authority with
    // inline_capacity == 6 (JSObject.h:1229). Build an object that crosses the 6->64
    // inline/out-of-line boundary and assert (a) offsets follow offsetForPropertyNumber
    // (identity below 6, then a jump to firstOutOfLineOffset == 64), and (b) GET/PUT
    // return each property's OWN value across the boundary (no wrong-slot read).
    #[test]
    fn structure_offsets_cross_inline_to_out_of_line_boundary_and_get_put_unchanged() {
        let mut host = CoreOpcodeDispatchHost::new();
        let object = host.objects.allocate_with_prototype(None);

        const N: u32 = 10; // 0..5 inline (offsets 0..5), 6..9 out-of-line (offsets 64..67)
        for i in 0..N {
            let key = CorePropertyKey::Identifier(2000 + i);
            host.objects
                .set_data_own(object, &key, RuntimeValue::from_i32(i as i32))
                .unwrap();
        }

        for i in 0..N {
            let key = CorePropertyKey::Identifier(2000 + i);
            // (a) offsetForPropertyNumber(i, 6): identity in the inline band, jump to 64.
            let expected_offset = offset_for_property_number(i as i32, 6);
            assert_eq!(
                object_property_offset(&host.objects, object, &key),
                Some(PropertyOffset::new(expected_offset)),
                "property {i} offset must follow the inline/out-of-line split",
            );
            // (b) GET returns this property's own value (slow + offset path agree).
            let CorePropertyKind::Data(value) = host
                .objects
                .get_own_property(object, &key)
                .unwrap()
                .expect("own property")
                .kind
            else {
                panic!("expected data property");
            };
            assert_eq!(
                value,
                RuntimeValue::from_i32(i as i32),
                "GET must return property {i}'s own value, not an aliased slot",
            );
        }

        // The 8th property is out-of-line (property number 7 -> offset 65). PUT it and
        // re-read; a neighbouring out-of-line property must be unchanged.
        let key8 = CorePropertyKey::Identifier(2007);
        assert_eq!(
            object_property_offset(&host.objects, object, &key8),
            Some(PropertyOffset::new(65)),
        );
        host.objects
            .set_data_own(object, &key8, RuntimeValue::from_i32(777))
            .unwrap();
        let CorePropertyKind::Data(updated) = host
            .objects
            .get_own_property(object, &key8)
            .unwrap()
            .unwrap()
            .kind
        else {
            panic!("data");
        };
        assert_eq!(updated, RuntimeValue::from_i32(777));
        let key6 = CorePropertyKey::Identifier(2006);
        let CorePropertyKind::Data(neighbour) = host
            .objects
            .get_own_property(object, &key6)
            .unwrap()
            .unwrap()
            .kind
        else {
            panic!("data");
        };
        assert_eq!(
            neighbour,
            RuntimeValue::from_i32(6),
            "the PUT must not alias a neighbouring out-of-line slot",
        );
    }

    // gc-r4 Batch 2: deleting a named property frees its offset into the structure's
    // recycle stack (a fresh per-object dictionary structure) while PRESERVING every
    // surviving property's offset; re-adding recycles the freed offset. Prove GET
    // returns each property's OWN value throughout (delete-then-readd, no wrong slot).
    #[test]
    fn dictionary_on_delete_then_readd_keeps_offsets_and_no_wrong_slot() {
        let mut host = CoreOpcodeDispatchHost::new();
        let object = host.objects.allocate_with_prototype(None);
        let a = CorePropertyKey::Identifier(3001);
        let b = CorePropertyKey::Identifier(3002);
        let c = CorePropertyKey::Identifier(3003);
        host.objects
            .set_data_own(object, &a, RuntimeValue::from_i32(10))
            .unwrap();
        host.objects
            .set_data_own(object, &b, RuntimeValue::from_i32(20))
            .unwrap();
        host.objects
            .set_data_own(object, &c, RuntimeValue::from_i32(30))
            .unwrap();
        assert_eq!(
            object_property_offset(&host.objects, object, &a),
            Some(PropertyOffset::new(0)),
        );
        assert_eq!(
            object_property_offset(&host.objects, object, &b),
            Some(PropertyOffset::new(1)),
        );
        assert_eq!(
            object_property_offset(&host.objects, object, &c),
            Some(PropertyOffset::new(2)),
        );

        let data_value = |host: &CoreOpcodeDispatchHost, key: &CorePropertyKey| {
            host.objects
                .get_own_property(object, key)
                .unwrap()
                .map(|property| match property.kind {
                    CorePropertyKind::Data(value) => value,
                    CorePropertyKind::Accessor { .. } => panic!("expected data property"),
                })
        };

        // Delete b: its offset is freed; a@0 and c@2 are preserved (and read correctly).
        assert!(host.objects.delete_property(object, &b).unwrap());
        assert_eq!(
            object_property_offset(&host.objects, object, &b),
            None,
            "a deleted key has no named offset",
        );
        assert_eq!(
            object_property_offset(&host.objects, object, &a),
            Some(PropertyOffset::new(0))
        );
        assert_eq!(
            object_property_offset(&host.objects, object, &c),
            Some(PropertyOffset::new(2))
        );
        assert_eq!(data_value(&host, &b), None, "deleted property is absent");
        assert_eq!(data_value(&host, &a), Some(RuntimeValue::from_i32(10)));
        assert_eq!(data_value(&host, &c), Some(RuntimeValue::from_i32(30)));

        // Re-add b with a NEW value: it recycles the freed offset (1) and reads back its
        // OWN value; a and c are still correct (no wrong-slot from the recycled slot).
        host.objects
            .set_data_own(object, &b, RuntimeValue::from_i32(99))
            .unwrap();
        assert_eq!(
            object_property_offset(&host.objects, object, &b),
            Some(PropertyOffset::new(1)),
            "re-add recycles the freed offset (PropertyTable::nextOffset)",
        );
        assert_eq!(data_value(&host, &b), Some(RuntimeValue::from_i32(99)));
        assert_eq!(data_value(&host, &a), Some(RuntimeValue::from_i32(10)));
        assert_eq!(data_value(&host, &c), Some(RuntimeValue::from_i32(30)));
    }

    #[test]
    fn generated_property_store_mutation_indexed_store_commits_existing_element_with_one_barrier() {
        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let array = host.objects.allocate_array();
        let original_value = RuntimeValue::from_i32(42);
        host.objects
            .put_array_element(array, 0, original_value)
            .unwrap();
        let stored_value = host.objects.allocate_with_prototype(None);
        let plan =
            generated_property_store_indexed_plan(object_structure_id(&host.objects, array), 0);
        let hit = store_probe_hit(host.probe_generated_property_store(
            generated_property_store_probe_request(&plan, array, stored_value),
        ));
        let request = GeneratedPropertyStoreMutationRequest::new(array, hit);
        let before = object_store_mutation_snapshot(&host.objects, array);

        let commit =
            store_mutation_commit(host.commit_generated_property_store(&mut heap, request));

        assert_eq!(
            commit,
            GeneratedPropertyStoreMutationCommit::host_confirmed_for_request(&request)
        );
        let mut expected = before.clone();
        expected.elements[0] = Some(stored_value);
        assert_eq!(
            expected,
            object_store_mutation_snapshot(&host.objects, array)
        );
        assert_eq!(host.objects.get_index(array, 0), Ok(stored_value));
        let array_handle = host.objects.find(array).expect("array").butterfly;
        assert_eq!(
            host.objects.butterfly_elem_len(array_handle),
            before.elements.len()
        );
        assert_single_value_store_barrier(
            &heap,
            BarrierRequirementOutcome::NotRequired(BarrierNotRequiredReason::TargetAlreadyVisible),
        );
    }

    #[test]
    fn generated_property_store_mutation_rejects_stale_and_invalid_live_state_without_barrier() {
        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let key = CorePropertyKey::Identifier(11);
        let stored_value = RuntimeValue::from_i32(99);

        let stale = host.objects.allocate_with_prototype(None);
        host.objects
            .set_data_own(stale, &key, RuntimeValue::from_i32(42))
            .unwrap();
        let stale_plan = generated_property_store_replace_plan(
            object_structure_id(&host.objects, stale),
            object_property_offset(&host.objects, stale, &key).expect("offset"),
            11,
        );
        host.objects
            .set_data_own(
                stale,
                &CorePropertyKey::Identifier(12),
                RuntimeValue::from_i32(1),
            )
            .unwrap();
        assert_store_mutation_rejects_without_barrier(
            &mut host,
            &mut heap,
            stale,
            generated_property_store_mutation_request(&stale_plan, stale, stored_value),
            GeneratedPropertyStoreMutationMissReason::StructureMismatch,
        );

        let missing = host.objects.allocate_with_prototype(None);
        let missing_plan = generated_property_store_replace_plan(
            object_structure_id(&host.objects, missing),
            PropertyOffset::new(0),
            11,
        );
        assert_store_mutation_rejects_without_barrier(
            &mut host,
            &mut heap,
            missing,
            generated_property_store_mutation_request(&missing_plan, missing, stored_value),
            GeneratedPropertyStoreMutationMissReason::ExistingPropertyMismatch,
        );

        let accessor = host.objects.allocate_with_prototype(None);
        host.objects
            .define_accessor(accessor, &key, None, None)
            .unwrap();
        let accessor_plan = generated_property_store_replace_plan(
            object_structure_id(&host.objects, accessor),
            PropertyOffset::new(0),
            11,
        );
        assert_store_mutation_rejects_without_barrier(
            &mut host,
            &mut heap,
            accessor,
            generated_property_store_mutation_request(&accessor_plan, accessor, stored_value),
            GeneratedPropertyStoreMutationMissReason::ExistingPropertyMismatch,
        );

        let offset_mismatch = host.objects.allocate_with_prototype(None);
        host.objects
            .set_data_own(offset_mismatch, &key, RuntimeValue::from_i32(42))
            .unwrap();
        let actual_offset =
            object_property_offset(&host.objects, offset_mismatch, &key).expect("offset");
        let offset_mismatch_plan = generated_property_store_replace_plan(
            object_structure_id(&host.objects, offset_mismatch),
            PropertyOffset::new(actual_offset.raw() + 1),
            11,
        );
        assert_store_mutation_rejects_without_barrier(
            &mut host,
            &mut heap,
            offset_mismatch,
            generated_property_store_mutation_request(
                &offset_mismatch_plan,
                offset_mismatch,
                stored_value,
            ),
            GeneratedPropertyStoreMutationMissReason::ExistingPropertyMismatch,
        );

        let replace_with_new_structure = host.objects.allocate_with_prototype(None);
        host.objects
            .set_data_own(replace_with_new_structure, &key, RuntimeValue::from_i32(42))
            .unwrap();
        let replace_with_new_structure_plan = generated_property_store_replace_plan(
            object_structure_id(&host.objects, replace_with_new_structure),
            object_property_offset(&host.objects, replace_with_new_structure, &key)
                .expect("offset"),
            11,
        );
        let mut replace_with_new_structure_request = generated_property_store_mutation_request(
            &replace_with_new_structure_plan,
            replace_with_new_structure,
            stored_value,
        );
        replace_with_new_structure_request
            .probe_hit
            .planned_new_structure = Some(host.objects.allocate_structure_id());
        assert_store_mutation_rejects_without_barrier(
            &mut host,
            &mut heap,
            replace_with_new_structure,
            replace_with_new_structure_request,
            GeneratedPropertyStoreMutationMissReason::TransitionStructureMismatch,
        );

        let transition_present = host.objects.allocate_with_prototype(None);
        host.objects
            .set_data_own(transition_present, &key, RuntimeValue::from_i32(42))
            .unwrap();
        let present_offset = host.objects.next_property_offset(transition_present);
        let present_new_structure = host.objects.allocate_structure_id();
        let present_plan = generated_property_store_transition_plan(
            object_structure_id(&host.objects, transition_present),
            present_offset,
            present_new_structure,
            11,
        );
        assert_store_mutation_rejects_without_barrier(
            &mut host,
            &mut heap,
            transition_present,
            generated_property_store_mutation_request(
                &present_plan,
                transition_present,
                stored_value,
            ),
            GeneratedPropertyStoreMutationMissReason::ExistingPropertyMismatch,
        );

        let transition_missing_structure = host.objects.allocate_with_prototype(None);
        let transition_missing_offset = host
            .objects
            .next_property_offset(transition_missing_structure);
        let transition_missing_new_structure = host.objects.allocate_structure_id();
        let transition_missing_plan = generated_property_store_transition_plan(
            object_structure_id(&host.objects, transition_missing_structure),
            transition_missing_offset,
            transition_missing_new_structure,
            11,
        );
        let mut missing_structure_request = generated_property_store_mutation_request(
            &transition_missing_plan,
            transition_missing_structure,
            stored_value,
        );
        missing_structure_request.probe_hit.planned_new_structure = None;
        assert_store_mutation_rejects_without_barrier(
            &mut host,
            &mut heap,
            transition_missing_structure,
            missing_structure_request,
            GeneratedPropertyStoreMutationMissReason::MissingTransitionStructure,
        );

        let transition_same_structure = host.objects.allocate_with_prototype(None);
        let transition_same_offset = host.objects.next_property_offset(transition_same_structure);
        let transition_same_new_structure = host.objects.allocate_structure_id();
        let transition_same_plan = generated_property_store_transition_plan(
            object_structure_id(&host.objects, transition_same_structure),
            transition_same_offset,
            transition_same_new_structure,
            11,
        );
        let mut same_structure_request = generated_property_store_mutation_request(
            &transition_same_plan,
            transition_same_structure,
            stored_value,
        );
        same_structure_request.probe_hit.planned_new_structure = Some(object_structure_id(
            &host.objects,
            transition_same_structure,
        ));
        assert_store_mutation_rejects_without_barrier(
            &mut host,
            &mut heap,
            transition_same_structure,
            same_structure_request,
            GeneratedPropertyStoreMutationMissReason::TransitionStructureMismatch,
        );

        let target = host.objects.allocate_with_prototype(None);
        let handler = host.objects.allocate_with_prototype(None);
        let proxy = host
            .objects
            .allocate_proxy_with_write_barrier(&mut heap, target, handler)
            .unwrap();
        let proxy_offset = host.objects.next_property_offset(proxy);
        let proxy_new_structure = host.objects.allocate_structure_id();
        let proxy_plan = generated_property_store_transition_plan(
            object_structure_id(&host.objects, proxy),
            proxy_offset,
            proxy_new_structure,
            11,
        );
        assert_store_mutation_rejects_without_barrier(
            &mut host,
            &mut heap,
            proxy,
            generated_property_store_mutation_request(&proxy_plan, proxy, stored_value),
            GeneratedPropertyStoreMutationMissReason::OpaqueObject,
        );

        let non_cell_plan =
            generated_property_store_replace_plan(StructureId::new(1), PropertyOffset::new(0), 11);
        let barrier_count = heap.barrier_classification_count();
        assert_eq!(
            store_mutation_miss_reason(host.commit_generated_property_store(
                &mut heap,
                generated_property_store_mutation_request(
                    &non_cell_plan,
                    RuntimeValue::from_i32(1),
                    stored_value,
                ),
            )),
            GeneratedPropertyStoreMutationMissReason::NonCellBase
        );
        assert_eq!(heap.barrier_classification_count(), barrier_count);
    }

    #[test]
    fn generated_property_store_mutation_boundary_has_no_sidecar_or_vm_wiring() {
        let source = include_str!("mod.rs");
        for forbidden in [
            concat!("GeneratedPropertyStore", "ExecutionSidecar"),
            concat!("property_store_", "sidecar"),
            concat!("execute_generated_", "property_store"),
            concat!("execute_", "property_store_", "sidecar_candidate"),
            concat!("record_generated_", "property_store_mutation"),
            concat!("generated_property_store_", "mutation_readiness"),
            concat!("VmGeneratedPropertyStore", "MutationReadiness"),
            concat!("CodeBlockMutationAuthority::", "VmMainThread"),
        ] {
            assert!(
                !source.contains(forbidden),
                "unexpected generated store wiring found: {forbidden}"
            );
        }
    }

    #[test]
    fn generated_guarded_property_load_default_dispatch_host_reports_unavailable() {
        let mut core = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let owner = CodeBlockId(CellId(120));
        let object = core.objects.allocate_with_prototype(None);
        let key = CorePropertyKey::Identifier(11);
        let plan =
            generated_guarded_property_load_plan(&mut core, &mut heap, owner, object, &key, 41, 11);
        let mut host = CountingHost {
            count: 0,
            return_at: 1,
            return_value: RuntimeValue::undefined(),
        };

        assert_eq!(
            guarded_probe_miss_reason(host.probe_generated_guarded_property_load(
                generated_guarded_property_load_probe_request(&plan, object)
            )),
            GeneratedGuardedPropertyLoadProbeMissReason::HostUnavailable
        );
    }

    #[test]
    fn generated_guarded_property_load_prototype_data_probe_hits_live_value() {
        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let owner = CodeBlockId(CellId(121));
        let prototype = host.objects.allocate_with_prototype(None);
        let object = host.objects.allocate_with_prototype(Some(prototype));
        let child = host.objects.allocate_with_prototype(None);
        let key = CorePropertyKey::Identifier(11);
        host.objects.set_data_own(prototype, &key, child).unwrap();
        let plan =
            generated_guarded_property_load_plan(&mut host, &mut heap, owner, object, &key, 43, 11);

        let cell_result = host.probe_generated_guarded_property_load(
            generated_guarded_property_load_probe_request(&plan, object),
        );
        assert_eq!(
            cell_result,
            GeneratedGuardedPropertyLoadProbeResult::Hit(GeneratedGuardedPropertyLoadProbeHit {
                value: child,
                destination_root_sync:
                    GeneratedPropertyLoadDestinationRootSync::TargetedRegisterRequiredForCell,
            })
        );
        match cell_result {
            GeneratedGuardedPropertyLoadProbeResult::Hit(hit) => {
                assert!(hit.destination_root_sync.requires_targeted_register_sync());
            }
            GeneratedGuardedPropertyLoadProbeResult::Miss(_) => unreachable!(),
        }

        let immediate = RuntimeValue::from_i32(73);
        host.objects
            .set_data_own(prototype, &key, immediate)
            .unwrap();
        let immediate_result = host.probe_generated_guarded_property_load(
            generated_guarded_property_load_probe_request(&plan, object),
        );
        assert_eq!(
            immediate_result,
            GeneratedGuardedPropertyLoadProbeResult::Hit(GeneratedGuardedPropertyLoadProbeHit {
                value: immediate,
                destination_root_sync:
                    GeneratedPropertyLoadDestinationRootSync::NotRequiredForImmediate,
            })
        );
        match immediate_result {
            GeneratedGuardedPropertyLoadProbeResult::Hit(hit) => {
                assert!(!hit.destination_root_sync.requires_targeted_register_sync());
            }
            GeneratedGuardedPropertyLoadProbeResult::Miss(_) => unreachable!(),
        }
    }

    // C++ JSC AccessCase::Load guards the receiver by STRUCTURE (m_structureID), not
    // identity, so a prototype-chain (holder) load resident plan must Hit for EVERY
    // same-structure receiver, not just the instance observed. This is exactly the
    // richards case: obj.run()/obj.isHeldOrSuspended() called across many
    // TaskControlBlock instances that share one structure with the method on the
    // shared prototype.
    #[test]
    fn generated_guarded_prototype_data_probe_hits_sibling_receiver_sharing_structure() {
        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let owner = CodeBlockId(CellId(141));
        let prototype = host.objects.allocate_with_prototype(None);
        // Two distinct receiver instances allocated with the same prototype + same
        // (empty) shape converge under one structure id (StructureTransitionTable /
        // seed_structure_id), matching C++ JSC same-shape-sibling Structure sharing.
        let observed_receiver = host.objects.allocate_with_prototype(Some(prototype));
        let sibling_receiver = host.objects.allocate_with_prototype(Some(prototype));
        let key = CorePropertyKey::Identifier(11);
        let method = host.objects.allocate_with_prototype(None);
        host.objects.set_data_own(prototype, &key, method).unwrap();

        // The two siblings must genuinely share one base structure for this test to
        // exercise the structure-only receiver guard.
        assert_eq!(
            object_structure_id(&host.objects, observed_receiver),
            object_structure_id(&host.objects, sibling_receiver)
        );
        assert_ne!(observed_receiver, sibling_receiver);

        let plan = generated_guarded_property_load_plan(
            &mut host,
            &mut heap,
            owner,
            observed_receiver,
            &key,
            61,
            11,
        );
        assert_eq!(
            plan.descriptor.requirement,
            PropertyLoadGuardRequirement::PrototypeChain
        );

        // The observed receiver hits.
        assert_eq!(
            host.probe_generated_guarded_property_load(
                generated_guarded_property_load_probe_request(&plan, observed_receiver)
            ),
            GeneratedGuardedPropertyLoadProbeResult::hit(method)
        );
        // The DISTINCT sibling receiver (different cell identity, same structure) must
        // ALSO hit -- previously this produced Miss::UnknownGuardObject and exited to
        // the interpreter on every distinct instance.
        assert_eq!(
            host.probe_generated_guarded_property_load(
                generated_guarded_property_load_probe_request(&plan, sibling_receiver)
            ),
            GeneratedGuardedPropertyLoadProbeResult::hit(method)
        );

        // A receiver with a DIFFERENT structure (own property added -> structure
        // transition) must NOT hit; the receiver structure recheck fires
        // GuardStructureMismatch (terminal), not a false hit.
        host.objects
            .set_data_own(
                sibling_receiver,
                &CorePropertyKey::Identifier(99),
                RuntimeValue::from_i32(7),
            )
            .unwrap();
        assert_ne!(
            object_structure_id(&host.objects, observed_receiver),
            object_structure_id(&host.objects, sibling_receiver)
        );
        assert_eq!(
            guarded_probe_miss_reason(host.probe_generated_guarded_property_load(
                generated_guarded_property_load_probe_request(&plan, sibling_receiver)
            )),
            GeneratedGuardedPropertyLoadProbeMissReason::GuardStructureMismatch
        );
    }

    // CORRECTNESS-CRITICAL: a wrong prototype-load hit returns the wrong method
    // (silent corruption). C++ JSC backs each conditionSet condition with a
    // structure-transition watchpoint on the prototype structure; when the prototype
    // shape changes the cached holder offset is no longer valid. The resident probe
    // mirrors this with a defensive holder-structure recheck: a prototype-shape change
    // MUST make the cached plan MISS (terminal), and a fresh re-observation must build
    // a new plan that loads the new value -- never the stale offset/method.
    #[test]
    fn generated_guarded_prototype_data_probe_invalidates_on_prototype_shape_change() {
        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let owner = CodeBlockId(CellId(142));
        let prototype = host.objects.allocate_with_prototype(None);
        let receiver = host.objects.allocate_with_prototype(Some(prototype));
        let key = CorePropertyKey::Identifier(11);
        let original_method = host.objects.allocate_with_prototype(None);
        host.objects
            .set_data_own(prototype, &key, original_method)
            .unwrap();

        let plan = generated_guarded_property_load_plan(
            &mut host, &mut heap, owner, receiver, &key, 63, 11,
        );
        assert_eq!(
            host.probe_generated_guarded_property_load(
                generated_guarded_property_load_probe_request(&plan, receiver)
            ),
            GeneratedGuardedPropertyLoadProbeResult::hit(original_method)
        );

        // Mutate the PROTOTYPE shape: adding a new own property transitions the
        // prototype's structure and (for the forward offset allocator) shifts the
        // holder offset of the cached key. The cached plan must NOT return the stale
        // method -- the holder-structure recheck must fire GuardStructureMismatch
        // (terminal), retiring the stale plan.
        let replacement_method = host.objects.allocate_with_prototype(None);
        host.objects
            .set_data_own(
                prototype,
                &CorePropertyKey::Identifier(98),
                RuntimeValue::from_i32(5),
            )
            .unwrap();
        host.objects
            .set_data_own(prototype, &key, replacement_method)
            .unwrap();
        assert_eq!(
            guarded_probe_miss_reason(host.probe_generated_guarded_property_load(
                generated_guarded_property_load_probe_request(&plan, receiver)
            )),
            GeneratedGuardedPropertyLoadProbeMissReason::GuardStructureMismatch
        );

        // Re-observing after the prototype reshape builds a fresh plan that loads the
        // CURRENT method, never the stale one.
        let refreshed_plan = generated_guarded_property_load_plan(
            &mut host, &mut heap, owner, receiver, &key, 65, 11,
        );
        assert_eq!(
            host.probe_generated_guarded_property_load(
                generated_guarded_property_load_probe_request(&refreshed_plan, receiver)
            ),
            GeneratedGuardedPropertyLoadProbeResult::hit(replacement_method)
        );
    }

