    fn allocate_test_code_block_id(heap: &mut Heap) -> CodeBlockId {
        let metadata = static_cell_metadata_registry()
            .metadata_for_type(CellType::CodeBlock)
            .map(|descriptor| descriptor.metadata)
            .expect("code block metadata");
        let allocation = heap
            .allocate_record(HeapAllocationRequest {
                heap: heap.id(),
                subspace: "auxiliary",
                metadata,
                byte_size: std::mem::size_of::<CodeBlock>().max(1),
                mode: AllocationMode::Normal,
                may_trigger_collection: false,
            })
            .expect("code block allocation");
        heap.publish_cell(allocation.cell)
            .expect("code block publication");
        CodeBlockId(allocation.cell)
    }

    #[derive(Default)]
    struct TargetedRootObservingHost {
        dispatch_roots: Vec<Vec<TargetedRootRecord>>,
    }

    impl DispatchHost for TargetedRootObservingHost {
        fn dispatch_instruction(
            &mut self,
            state: &mut DispatchState<'_>,
            _instruction: DispatchInstruction<'_>,
        ) -> DispatchOutcome {
            self.dispatch_roots
                .push(state.heap.targeted_roots().records().to_vec());
            DispatchOutcome::Return(RuntimeValue::undefined())
        }
    }

    // Faithful steady-state value-store barrier check.
    //
    // The owner is fresh/DefinitelyWhite, so the store is outside barrierThreshold == 0
    // (HeapInlines.h:106): exactly one barrier FORM is classified (JSC selects the form at
    // compile time, write-barriers.md:9 — our per-store classification counter mirrors that),
    // the classification `outcome` is recorded as the last outcome, and the slow path adds
    // nothing to the remembered set so `barriers_executed` stays 0 (Heap.cpp:1190,1919). The
    // former helpers asserted the deleted unbounded Vec of records with a fabricated
    // PossiblyBlack owner / PossiblyGrey target and a Required(MarkingBarrier) outcome — that
    // was accidental Rust behavior, not JSC's near-free not-collecting barrier.
    fn assert_single_value_store_barrier(heap: &Heap, outcome: BarrierRequirementOutcome) {
        assert_value_store_barrier_at(heap, 0, outcome);
    }

    fn assert_value_store_barrier_at(
        heap: &Heap,
        start: usize,
        outcome: BarrierRequirementOutcome,
    ) {
        assert_eq!(heap.barrier_classification_count(), start + 1);
        assert_eq!(heap.last_barrier_outcome(), Some(outcome));
        assert_eq!(heap.barriers_executed(), 0);
    }

    fn single_register_snapshot(heap: &Heap, value: RuntimeValue) -> ExecutionRootSnapshot {
        let mut stack = ExecutionContextStack::default();
        let mut registers = RegisterFile::default();
        stack.enter(ExecutionEntryRecord::Program(ProgramExecutionEntry {
            code_block: CodeBlockId(CellId(11)),
            global_object: GlobalObjectId(ObjectId(CellId(12))),
            this_value: RuntimeValue::undefined(),
        }));
        stack
            .push_frame(
                &mut registers,
                FramePushRequest {
                    code_block: None,
                    callee: None,
                    callee_value: None,
                    lexical_scope: None,
                    shape: RegisterFrameShape {
                        num_parameters_including_this: 1,
                        num_vars: 0,
                        num_callee_locals: 0,
                        num_temporaries: 0,
                        special: Default::default(),
                    },
                    argument_count_including_this: 1,
                    argument_values: vec![value],
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
                None,
            )
            .unwrap();
        stack
            .root_snapshot(heap.id(), &registers)
            .expect("valid roots")
    }

    fn dispatch_state<'a>(
        stack: &'a mut ExecutionContextStack,
        registers: &'a mut RegisterFile,
        exceptions: &'a mut ExceptionState,
        heap: &'a mut Heap,
        code_block: &'a CodeBlock,
    ) -> DispatchState<'a> {
        DispatchState {
            stack,
            registers,
            exceptions,
            heap,
            code_block,
            ordinary_bytecode_call_handling: OrdinaryBytecodeCallHandling::DirectInterpreter,
            function_value_call_handling: FunctionValueCallHandling::DirectInterpreter,
        }
    }

    #[test]
    fn core_string_store_binds_untracked_string_when_heap_path_reuses_intern() {
        // gc-r4-completion U1: the string CELL lives in the SHARED arena (CoreObjectStore),
        // the StringImpl payload + heap-binding id in the store's `string_records` slab.
        let mut objects = CoreObjectStore::default();
        let mut strings = CoreStringStore::default();
        let mut heap = Heap::new();
        let untracked = strings.allocate_untracked(&mut objects, "seeded");
        let payload = cell_payload(untracked);
        assert_eq!(heap.cell_for_payload(payload), None);

        let rebound = strings
            .allocate_with_heap(&mut objects, &mut heap, "seeded")
            .unwrap();

        assert_eq!(rebound, untracked);
        let cell = heap_cell_for_value(&heap, rebound);
        assert_ne!(cell, CellId::default());
        assert_eq!(heap.payload_for_cell(cell), Some(payload));
        let slot = strings.index_for_value(rebound).unwrap();
        assert_eq!(strings.string_records[slot].cell_id, cell);
    }

