    #[test]
    fn frame_push_and_pop_validate_lifo_and_release_registers() {
        let mut stack = ExecutionContextStack::default();
        let mut registers = RegisterFile::default();
        let code_block_id = CodeBlockId(CellId(7));
        let entry = stack.enter(ExecutionEntryRecord::Eval(EvalExecutionEntry {
            code_block: code_block_id,
            this_value: RuntimeValue::undefined(),
            scope: ScopeId(3),
            direct: true,
        }));
        let frame = stack
            .push_frame(
                &mut registers,
                FramePushRequest {
                    code_block: Some(code_block_id),
                    callee: None,
                    callee_value: None,
                    lexical_scope: Some(ScopeId(3)),
                    shape: RegisterFrameShape {
                        num_parameters_including_this: 1,
                        num_vars: 2,
                        num_callee_locals: 2,
                        num_temporaries: 0,
                        special: Default::default(),
                    },
                    argument_count_including_this: 1,
                    argument_values: vec![RuntimeValue::from_i32(42)],
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
                None,
            )
            .unwrap();

        assert_eq!(stack.frame_depth(), 1);
        assert_eq!(registers.register_count(), 3);
        let installed = stack.top_frame().unwrap().clone();
        assert_eq!(
            registers
                .read(
                    installed.register_window,
                    VirtualRegister::argument_or_header(5),
                    None,
                )
                .unwrap(),
            RuntimeValue::from_i32(42)
        );
        stack.pop_frame(&mut registers, frame).unwrap();
        assert_eq!(registers.register_count(), 0);
        let exit = stack.leave(entry).unwrap();
        assert_eq!(exit.kind, ExecutionEntryKind::Eval);
    }

    // B3 dual-write: a nested call tree (A -> B -> C, each with args) must keep
    // the JsStack arena shadow byte-identical to the `InstalledCallFrame` chain
    // at EVERY depth, the `CallFrameId <-> FrameAddress` table must round-trip,
    // and frame pops must restore the arena SP in lockstep. Gated to `unix`
    // because the shadow arena is `mmap`-backed (`JsStack::new`).
    #[cfg(unix)]
    #[test]
    fn b3_dual_write_shadow_tracks_nested_call_tree_byte_identically() {
        use crate::bytecode::register::RegisterFrameShape;

        let mut stack = ExecutionContextStack::default();
        let mut registers = RegisterFile::default();

        let shape = |callee_locals: u32| RegisterFrameShape {
            num_parameters_including_this: 1,
            num_vars: 1,
            num_callee_locals: callee_locals,
            num_temporaries: 0,
            special: Default::default(),
        };

        let entry = stack.enter(ExecutionEntryRecord::Program(ProgramExecutionEntry {
            code_block: CodeBlockId(CellId(100)),
            global_object: GlobalObjectId(ObjectId(CellId(1))),
            this_value: RuntimeValue::undefined(),
        }));

        // --- Frame A: VM-entry frame (no JS caller), this + 1 arg ---
        let a_this = RuntimeValue::from_i32(10);
        let a_arg0 = RuntimeValue::from_i32(11);
        let id_a = stack
            .push_frame(
                &mut registers,
                FramePushRequest {
                    code_block: Some(CodeBlockId(CellId(101))),
                    callee: Some(ObjectId(CellId(201))),
                    callee_value: None,
                    lexical_scope: None,
                    shape: shape(2),
                    argument_count_including_this: 2,
                    argument_values: vec![a_this, a_arg0],
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
                // K1: this bare-stack test has no `CodeBlockRegistry`, so it seeds
                // slot 2 with a synthetic non-null `CodeBlock*` sentinel (never
                // dereferenced) whose bits equal the old `CellId` value (101/102/
                // 103). That preserves the per-frame slot-2 discrimination the
                // `code_block_bits` assertions below check, now under the K1
                // "slot 2 holds a real `CodeBlock*`" contract.
                Some(101_usize as *const CodeBlock),
            )
            .unwrap();

        // The shadow activates on the first push (mmap arena).
        assert_eq!(registers.shadow_depth(), 1);
        let addr_a = registers.shadow_address_of(id_a).expect("A mirrored");
        let sp_at_a = registers.shadow_current_stack_pointer().unwrap();
        // B4 FULL-WINDOW: the arena SP descends past A's reserved locals, so it is
        // A's `fp` minus the locals region (shape(2) -> local_count 2 -> 16 bytes),
        // NOT `fp` itself.
        assert_eq!(
            sp_at_a,
            addr_a.0 - 2 * 8,
            "arena SP == A's fp - locals after seeding A"
        );

        // A's slot 0 is the EntryFrame sentinel (no JS caller).
        let image_a = registers.shadow_frame_header_image(addr_a).unwrap();
        assert_eq!(
            image_a.caller_frame_bits,
            entry_frame_sentinel_bits(Some(entry)) as usize
        );
        assert_eq!(image_a.code_block_bits, 101);
        assert_eq!(image_a.callee_bits, 201);
        assert_eq!(image_a.argument_count_including_this, 2);
        assert_eq!(image_a.this_value.js_value(), a_this);
        assert_eq!(
            registers.shadow_frame_argument_value(addr_a, 0),
            Some(a_arg0)
        );

        // --- Frame B: nested under A, this + 2 args ---
        let b_this = RuntimeValue::from_i32(20);
        let b_arg0 = RuntimeValue::from_i32(21);
        let b_arg1 = RuntimeValue::from_i32(22);
        let id_b = stack
            .push_frame(
                &mut registers,
                FramePushRequest {
                    code_block: Some(CodeBlockId(CellId(102))),
                    callee: Some(ObjectId(CellId(202))),
                    callee_value: None,
                    lexical_scope: None,
                    shape: shape(3),
                    argument_count_including_this: 3,
                    argument_values: vec![b_this, b_arg0, b_arg1],
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
                Some(102_usize as *const CodeBlock),
            )
            .unwrap();

        assert_eq!(registers.shadow_depth(), 2);
        let addr_b = registers.shadow_address_of(id_b).expect("B mirrored");
        let sp_at_b = registers.shadow_current_stack_pointer().unwrap();
        // B's locals (shape(3) -> local_count 3 -> 24 bytes) are reserved below
        // B's fp.
        assert_eq!(sp_at_b, addr_b.0 - 3 * 8);
        // B sits strictly BELOW A's whole window incl. A's locals (the arena grows
        // down and B was seeded from A's post-locals SP).
        assert!(addr_b.0 < addr_a.0, "B's frame is below A's");
        assert!(addr_b.0 <= sp_at_a, "B's fp is at/below A's post-locals SP");

        // B's slot 0 links to A's arena address (a genuine linked frame chain).
        let image_b = registers.shadow_frame_header_image(addr_b).unwrap();
        assert_eq!(image_b.caller_frame_bits, addr_a.0);
        assert_eq!(image_b.code_block_bits, 102);
        assert_eq!(image_b.callee_bits, 202);
        assert_eq!(image_b.argument_count_including_this, 3);
        assert_eq!(image_b.this_value.js_value(), b_this);
        assert_eq!(
            registers.shadow_frame_argument_value(addr_b, 0),
            Some(b_arg0)
        );
        assert_eq!(
            registers.shadow_frame_argument_value(addr_b, 1),
            Some(b_arg1)
        );

        // A stays byte-identical after B was seeded below it (no clobber).
        let image_a_after = registers.shadow_frame_header_image(addr_a).unwrap();
        assert_eq!(image_a_after, image_a);

        // --- Frame C: nested under B, this only (no args) ---
        let c_this = RuntimeValue::from_i32(30);
        let id_c = stack
            .push_frame(
                &mut registers,
                FramePushRequest {
                    code_block: Some(CodeBlockId(CellId(103))),
                    callee: None,
                    callee_value: None,
                    lexical_scope: None,
                    shape: shape(1),
                    argument_count_including_this: 1,
                    argument_values: vec![c_this],
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
                Some(103_usize as *const CodeBlock),
            )
            .unwrap();

        assert_eq!(registers.shadow_depth(), 3);
        let addr_c = registers.shadow_address_of(id_c).expect("C mirrored");
        let sp_at_c = registers.shadow_current_stack_pointer().unwrap();
        // C's locals (shape(1) -> local_count 1 -> 8 bytes) below C's fp.
        assert_eq!(sp_at_c, addr_c.0 - 8);
        assert!(addr_c.0 < addr_b.0, "C's frame is below B's");
        assert!(addr_c.0 <= sp_at_b, "C's fp is at/below B's post-locals SP");

        let image_c = registers.shadow_frame_header_image(addr_c).unwrap();
        assert_eq!(image_c.caller_frame_bits, addr_b.0);
        assert_eq!(image_c.code_block_bits, 103);
        assert_eq!(image_c.callee_bits, 0, "no callee -> null callee slot");
        assert_eq!(image_c.argument_count_including_this, 1);
        assert_eq!(image_c.this_value.js_value(), c_this);

        // --- CallFrameId <-> FrameAddress table round-trips for every frame ---
        assert_eq!(registers.shadow_frame_id_at(addr_a), Some(id_a));
        assert_eq!(registers.shadow_frame_id_at(addr_b), Some(id_b));
        assert_eq!(registers.shadow_frame_id_at(addr_c), Some(id_c));
        // Distinct addresses for distinct frames.
        assert_ne!(addr_a.0, addr_b.0);
        assert_ne!(addr_b.0, addr_c.0);

        // --- Pop C, B, A: the arena SP rises in lockstep with each release ---
        stack.pop_frame(&mut registers, id_c).unwrap();
        assert_eq!(registers.shadow_depth(), 2);
        assert_eq!(registers.shadow_current_stack_pointer(), Some(sp_at_b));

        stack.pop_frame(&mut registers, id_b).unwrap();
        assert_eq!(registers.shadow_depth(), 1);
        assert_eq!(registers.shadow_current_stack_pointer(), Some(sp_at_a));

        stack.pop_frame(&mut registers, id_a).unwrap();
        assert_eq!(registers.shadow_depth(), 0);
        // After the last pop the arena SP returns to the pre-A top: A's FULL
        // window was header(5) + paddedArgs(2) + locals(2) = 9 registers = 72
        // bytes (sp_at_a is already below A's locals).
        assert_eq!(
            registers.shadow_current_stack_pointer(),
            Some(sp_at_a + 9 * 8)
        );
    }

    // B4 READ-FLIP: with reads served from the JsStack arena window, a function
    // with locals + temporaries + nested calls must read back EVERY
    // VirtualRegister (locals, `this`, args) at EVERY depth byte-identically to
    // the `Vec` oracle. `RegisterFile::read` debug-asserts `arena == Vec` on every
    // read, so this test (run with debug_assertions) PROVES the offset mapping
    // `fp + vreg.raw()*8` is byte-faithful over the full window — a sign or
    // off-by-one error would fire the assert. Gated to `unix` (mmap arena).
    #[cfg(unix)]
    #[test]
    fn b4_read_flip_full_window_arena_equals_vec_across_locals_and_nested_calls() {
        let this_offset = CallFrameSlotLayout::JSC_RUST.this_argument_offset;
        let mut stack = ExecutionContextStack::default();
        let mut registers = RegisterFile::default();

        // local_count = max(num_callee_locals 4, num_vars 2 + num_temporaries 2) = 4.
        let shape = RegisterFrameShape {
            num_parameters_including_this: 2,
            num_vars: 2,
            num_callee_locals: 4,
            num_temporaries: 2,
            special: Default::default(),
        };

        let entry = stack.enter(ExecutionEntryRecord::Program(ProgramExecutionEntry {
            code_block: CodeBlockId(CellId(100)),
            global_object: GlobalObjectId(ObjectId(CellId(1))),
            this_value: RuntimeValue::undefined(),
        }));

        // --- Frame A: this + 1 arg, 4 locals/temporaries ---
        let id_a = stack
            .push_frame(
                &mut registers,
                FramePushRequest {
                    code_block: Some(CodeBlockId(CellId(101))),
                    callee: Some(ObjectId(CellId(201))),
                    callee_value: None,
                    lexical_scope: None,
                    shape,
                    argument_count_including_this: 2,
                    argument_values: vec![
                        RuntimeValue::from_i32(1000), // this
                        RuntimeValue::from_i32(1001), // arg0
                    ],
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
                None,
            )
            .unwrap();
        // The arena is active, so `read` is served from it (not the Vec fallback).
        assert_eq!(registers.shadow_depth(), 1);
        let window_a = stack.frame(id_a).unwrap().register_window;

        // Write distinct values to A's locals (incl. a temporary at local 3) and
        // overwrite arg0; each later `read` cross-checks arena == Vec internally.
        let a_locals = [10i32, 11, 12, 13];
        for (i, payload) in a_locals.iter().enumerate() {
            registers
                .write(
                    window_a,
                    VirtualRegister::local(i as u32),
                    RuntimeValue::from_i32(*payload),
                )
                .unwrap();
        }
        registers
            .write(
                window_a,
                VirtualRegister::argument_including_this(1, this_offset),
                RuntimeValue::from_i32(1999),
            )
            .unwrap();

        let read_a = |registers: &RegisterFile, vreg: VirtualRegister| {
            registers.read(window_a, vreg, None).unwrap()
        };
        for (i, payload) in a_locals.iter().enumerate() {
            assert_eq!(
                read_a(&registers, VirtualRegister::local(i as u32)),
                RuntimeValue::from_i32(*payload)
            );
        }
        // `this` unchanged; arg0 reflects the overwrite.
        assert_eq!(
            read_a(
                &registers,
                VirtualRegister::argument_including_this(0, this_offset)
            ),
            RuntimeValue::from_i32(1000)
        );
        assert_eq!(
            read_a(
                &registers,
                VirtualRegister::argument_including_this(1, this_offset)
            ),
            RuntimeValue::from_i32(1999)
        );

        // --- Frame B: nested under A, this + 2 args, own locals ---
        let id_b = stack
            .push_frame(
                &mut registers,
                FramePushRequest {
                    code_block: Some(CodeBlockId(CellId(102))),
                    callee: Some(ObjectId(CellId(202))),
                    callee_value: None,
                    lexical_scope: None,
                    shape,
                    argument_count_including_this: 3,
                    argument_values: vec![
                        RuntimeValue::from_i32(2000), // this
                        RuntimeValue::from_i32(2001), // arg0
                        RuntimeValue::from_i32(2002), // arg1
                    ],
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
                None,
            )
            .unwrap();
        assert_eq!(registers.shadow_depth(), 2);
        let window_b = stack.frame(id_b).unwrap().register_window;

        let b_locals = [20i32, 21, 22, 23];
        for (i, payload) in b_locals.iter().enumerate() {
            registers
                .write(
                    window_b,
                    VirtualRegister::local(i as u32),
                    RuntimeValue::from_i32(*payload),
                )
                .unwrap();
        }
        for (i, payload) in b_locals.iter().enumerate() {
            assert_eq!(
                registers
                    .read(window_b, VirtualRegister::local(i as u32), None)
                    .unwrap(),
                RuntimeValue::from_i32(*payload)
            );
        }
        assert_eq!(
            registers
                .read(
                    window_b,
                    VirtualRegister::argument_including_this(0, this_offset),
                    None
                )
                .unwrap(),
            RuntimeValue::from_i32(2000)
        );
        assert_eq!(
            registers
                .read(
                    window_b,
                    VirtualRegister::argument_including_this(2, this_offset),
                    None
                )
                .unwrap(),
            RuntimeValue::from_i32(2002)
        );

        // CRUCIAL: A's window is undisturbed by B's push (B is reserved strictly
        // BELOW A's locals). Re-read A at depth 2 — still arena==Vec for every
        // vreg, proving nested frames do not clobber the caller's full window.
        for (i, payload) in a_locals.iter().enumerate() {
            assert_eq!(
                read_a(&registers, VirtualRegister::local(i as u32)),
                RuntimeValue::from_i32(*payload)
            );
        }
        assert_eq!(
            read_a(
                &registers,
                VirtualRegister::argument_including_this(1, this_offset)
            ),
            RuntimeValue::from_i32(1999)
        );

        // --- Unwind: A stays consistent after B pops ---
        stack.pop_frame(&mut registers, id_b).unwrap();
        assert_eq!(registers.shadow_depth(), 1);
        for (i, payload) in a_locals.iter().enumerate() {
            assert_eq!(
                read_a(&registers, VirtualRegister::local(i as u32)),
                RuntimeValue::from_i32(*payload)
            );
        }
        stack.pop_frame(&mut registers, id_a).unwrap();
        let _ = stack.leave(entry).unwrap();
        assert_eq!(registers.register_count(), 0);
    }

    #[test]
    fn execution_root_snapshot_uses_stack_reachable_register_windows() {
        let mut stack = ExecutionContextStack::default();
        let mut registers = RegisterFile::default();
        let heap = Heap::new();
        let code_block_id = CodeBlockId(CellId(8));
        stack.enter(ExecutionEntryRecord::Program(ProgramExecutionEntry {
            code_block: code_block_id,
            global_object: GlobalObjectId(ObjectId(CellId(1))),
            this_value: RuntimeValue::undefined(),
        }));
        let frame = stack
            .push_frame(
                &mut registers,
                FramePushRequest {
                    code_block: Some(code_block_id),
                    callee: None,
                    callee_value: None,
                    lexical_scope: None,
                    shape: RegisterFrameShape {
                        num_parameters_including_this: 1,
                        num_vars: 1,
                        num_callee_locals: 0,
                        num_temporaries: 0,
                        special: Default::default(),
                    },
                    argument_count_including_this: 1,
                    argument_values: vec![RuntimeValue::from_i32(42)],
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
                None,
            )
            .unwrap();
        let live_window = stack.frame(frame).unwrap().register_window;
        registers.windows.push(live_window);

        assert_eq!(
            registers
                .root_descriptors(heap.id())
                .iter()
                .filter(|descriptor| descriptor.root.id == register_root_id(live_window.base))
                .count(),
            2
        );

        let snapshot = stack.root_snapshot(heap.id(), &registers).unwrap();
        assert_eq!(
            snapshot
                .register_roots
                .iter()
                .filter(|descriptor| descriptor.root.id == register_root_id(live_window.base))
                .count(),
            1
        );
    }

    #[test]
    fn dynamic_frame_and_register_roots_use_reserved_high_namespaces() {
        let frame_root = frame_root_id(CallFrameId(250_000), FrameRootSource::CodeBlock);
        let global_root = crate::vm::global_root_id(GlobalObjectId(ObjectId(CellId(1))));
        assert_ne!(frame_root, global_root);
        assert!(frame_root.0 >= FRAME_ROOT_ID_BASE);

        let register_root = register_root_id(3_000_000);
        assert_ne!(register_root, global_root);
        assert!(register_root.0 >= REGISTER_ROOT_ID_BASE);
    }

