    #[test]
    fn baseline_helpers_match_load_move_return_dispatch_semantics() {
        let source = VirtualRegister::local(0);
        let destination = VirtualRegister::local(1);
        let block = code_block(vec![
            core_typed(
                0,
                CoreOpcode::LoadInt32,
                vec![Operand::Register(source), Operand::SignedImmediate(7)],
            ),
            core_typed(
                1,
                CoreOpcode::Move,
                vec![Operand::Register(destination), Operand::Register(source)],
            ),
            core_typed(2, CoreOpcode::Return, vec![Operand::Register(destination)]),
        ]);
        let code_block_id = CodeBlockId(CellId(93));
        let mut dispatch_stack = ExecutionContextStack::default();
        let mut dispatch_registers = RegisterFile::default();
        let mut dispatch_exceptions = ExceptionState::default();
        let mut dispatch_heap = Heap::new();
        enter_program_frame(
            &mut dispatch_stack,
            &mut dispatch_registers,
            code_block_id,
            &block,
            Vec::new(),
        );
        let mut dispatch_host = CoreOpcodeDispatchHost::new();

        let dispatch_result = execute_code_block(
            InterpreterExecutionState {
                stack: &mut dispatch_stack,
                registers: &mut dispatch_registers,
                exceptions: &mut dispatch_exceptions,
                heap: &mut dispatch_heap,
            },
            code_block_id,
            &block,
            &mut dispatch_host,
            DispatchConfig::default(),
        );

        assert_eq!(
            dispatch_result,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(7))
        );

        let mut baseline_stack = ExecutionContextStack::default();
        let mut baseline_registers = RegisterFile::default();
        enter_program_frame(
            &mut baseline_stack,
            &mut baseline_registers,
            code_block_id,
            &block,
            Vec::new(),
        );
        let expected_frame = baseline_stack.top_frame().unwrap().id;
        let (frame, window) =
            baseline_active_frame(&baseline_stack, expected_frame, code_block_id).unwrap();

        baseline_write_register(
            &mut baseline_registers,
            window,
            source,
            RuntimeValue::from_i32(7),
        )
        .unwrap();
        let moved = baseline_read_register(&baseline_registers, &block, window, source).unwrap();
        baseline_write_register(&mut baseline_registers, window, destination, moved).unwrap();
        let returned =
            baseline_return_register(&baseline_registers, &block, window, destination).unwrap();

        assert_eq!(window, frame.register_window);
        assert_eq!(ExecutionCompletion::Returned(returned), dispatch_result);
        assert_eq!(
            baseline_registers
                .read(window, destination, Some(block.constants()))
                .unwrap(),
            RuntimeValue::from_i32(7)
        );
        // C++ JSC divergence: register/stack stores are not barriered, so there
        // is no per-write handoff stream to compare between the two paths. The
        // faithful equivalence is that the baseline helpers and the dispatch
        // loop leave the destination register holding the same moved value.
        assert_eq!(
            baseline_registers
                .read(window, destination, Some(block.constants()))
                .unwrap(),
            dispatch_registers
                .read(window, destination, Some(block.constants()))
                .unwrap()
        );
    }

