    #[test]
    fn baseline_fallback_rejects_missing_frame_or_invalid_bytecode_index() {
        struct PanicHost;
        impl DispatchHost for PanicHost {
            fn dispatch_instruction(
                &mut self,
                _state: &mut DispatchState<'_>,
                _instruction: DispatchInstruction<'_>,
            ) -> DispatchOutcome {
                unreachable!("fallback validation should reject before dispatch");
            }
        }

        let block = code_block(vec![typed(0)]);
        let code_block_id = CodeBlockId(CellId(90));
        let mut stack = ExecutionContextStack::default();
        let mut registers = RegisterFile::default();
        let mut exceptions = ExceptionState::default();
        let mut heap = Heap::new();
        let mut host = PanicHost;

        let missing_frame = execute_baseline_fallback(
            InterpreterExecutionState {
                stack: &mut stack,
                registers: &mut registers,
                exceptions: &mut exceptions,
                heap: &mut heap,
            },
            BaselineFallbackRequest::new(
                code_block_id,
                CallFrameId(1),
                BytecodeIndex::from_offset(0),
            ),
            &block,
            &mut host,
            DispatchConfig::default(),
        );

        assert_eq!(
            missing_frame,
            ExecutionCompletion::Failed(ExecutionError::NoActiveFrame)
        );

        enter_program_frame(
            &mut stack,
            &mut registers,
            code_block_id,
            &block,
            Vec::new(),
        );
        let frame = stack.top_frame().unwrap().id;

        let wrong_code_block = CodeBlockId(CellId(92));
        let code_block_mismatch = execute_baseline_fallback(
            InterpreterExecutionState {
                stack: &mut stack,
                registers: &mut registers,
                exceptions: &mut exceptions,
                heap: &mut heap,
            },
            BaselineFallbackRequest::new(wrong_code_block, frame, BytecodeIndex::from_offset(0)),
            &block,
            &mut host,
            DispatchConfig::default(),
        );

        assert_eq!(
            code_block_mismatch,
            ExecutionCompletion::Failed(ExecutionError::CodeBlockMismatch {
                expected: wrong_code_block,
                actual: Some(code_block_id),
            })
        );

        let invalid_index = execute_baseline_fallback(
            InterpreterExecutionState {
                stack: &mut stack,
                registers: &mut registers,
                exceptions: &mut exceptions,
                heap: &mut heap,
            },
            BaselineFallbackRequest::new(code_block_id, frame, BytecodeIndex::from_offset(1)),
            &block,
            &mut host,
            DispatchConfig::default(),
        );

        assert_eq!(
            invalid_index,
            ExecutionCompletion::Failed(ExecutionError::InvalidBytecodeIndex(
                BytecodeIndex::from_offset(1)
            ))
        );
        assert_eq!(
            stack.top_frame().unwrap().bytecode_index,
            Some(BytecodeIndex::from_offset(0))
        );
    }

    #[test]
    fn baseline_fallback_resumes_at_requested_bytecode_index() {
        struct RecordingHost {
            seen: Vec<BytecodeIndex>,
        }

        impl DispatchHost for RecordingHost {
            fn dispatch_instruction(
                &mut self,
                _state: &mut DispatchState<'_>,
                instruction: DispatchInstruction<'_>,
            ) -> DispatchOutcome {
                self.seen.push(instruction.bytecode_index);
                DispatchOutcome::Return(RuntimeValue::from_i32(42))
            }
        }

        let block = code_block(vec![typed(0), typed(1)]);
        let code_block_id = CodeBlockId(CellId(91));
        let mut stack = ExecutionContextStack::default();
        let mut registers = RegisterFile::default();
        let mut exceptions = ExceptionState::default();
        let mut heap = Heap::new();
        enter_program_frame(
            &mut stack,
            &mut registers,
            code_block_id,
            &block,
            Vec::new(),
        );
        let frame = stack.top_frame().unwrap().id;
        let mut host = RecordingHost { seen: Vec::new() };

        let result = execute_baseline_fallback(
            InterpreterExecutionState {
                stack: &mut stack,
                registers: &mut registers,
                exceptions: &mut exceptions,
                heap: &mut heap,
            },
            BaselineFallbackRequest::new(code_block_id, frame, BytecodeIndex::from_offset(1)),
            &block,
            &mut host,
            DispatchConfig::default(),
        );

        assert_eq!(
            result,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        assert_eq!(host.seen, vec![BytecodeIndex::from_offset(1)]);
        assert_eq!(
            stack.top_frame().unwrap().bytecode_index,
            Some(BytecodeIndex::from_offset(1))
        );
    }

