    fn wide_program_code_block(instructions: Vec<TypedInstruction>) -> CodeBlock {
        code_block_with_frame(
            instructions,
            RegisterFrameShape {
                num_parameters_including_this: 1,
                num_vars: 8,
                num_callee_locals: 0,
                num_temporaries: 0,
                special: Default::default(),
            },
        )
    }

    fn continuation_validation_fixture() -> (
        ExecutionContextStack,
        RegisterFile,
        Heap,
        CodeBlock,
        CodeBlockId,
        CallFrameId,
        RegisterWindow,
    ) {
        let block = wide_program_code_block(vec![typed(0)]);
        let owner = CodeBlockId(CellId(70));
        let mut stack = ExecutionContextStack::default();
        let mut registers = RegisterFile::default();
        let heap = Heap::new();
        enter_program_frame(&mut stack, &mut registers, owner, &block, Vec::new());
        let frame = stack.top_frame().unwrap().id;
        let window = stack.top_frame().unwrap().register_window;
        (stack, registers, heap, block, owner, frame, window)
    }

    fn valid_continuation_request(
        owner: CodeBlockId,
        frame: CallFrameId,
        window: RegisterWindow,
    ) -> CallReturnContinuationRequest {
        CallReturnContinuationRequest {
            caller_frame: frame,
            caller_window: window,
            owner,
            call_bytecode_index: BytecodeIndex::from_offset(0),
            resume_bytecode_index: Some(BytecodeIndex::from_offset(1)),
            destination: local(0),
            argument_count_including_this: 1,
            callee_value: Some(RuntimeValue::undefined()),
            kind: CallReturnKind::Call,
        }
    }

    #[test]
    fn call_return_continuation_creation_rejects_invalid_identity_and_destination() {
        let (stack, registers, heap, _block, owner, frame, window) =
            continuation_validation_fixture();

        let continuation = create_call_return_continuation(
            &stack,
            &registers,
            &heap,
            valid_continuation_request(owner, frame, window),
        )
        .unwrap();
        assert_eq!(continuation.caller_frame, frame);
        assert_eq!(continuation.owner, owner);
        assert_eq!(continuation.destination, local(0));

        let mut wrong_owner = valid_continuation_request(owner, frame, window);
        wrong_owner.owner = CodeBlockId(CellId(71));
        assert_eq!(
            create_call_return_continuation(&stack, &registers, &heap, wrong_owner),
            Err(ExecutionError::CodeBlockMismatch {
                expected: CodeBlockId(CellId(71)),
                actual: Some(owner),
            })
        );

        let mut invalid_destination = valid_continuation_request(owner, frame, window);
        invalid_destination.destination = VirtualRegister::constant(0);
        assert_eq!(
            create_call_return_continuation(&stack, &registers, &heap, invalid_destination),
            Err(ExecutionError::CannotWriteConstant)
        );

        let mut stale_registers = registers.clone();
        stale_registers
            .allocate_frame(
                CallFrameId(900),
                RegisterFrameShape {
                    num_parameters_including_this: 1,
                    num_vars: 1,
                    num_callee_locals: 0,
                    num_temporaries: 0,
                    special: Default::default(),
                },
                1,
                &[],
            )
            .unwrap();
        assert_eq!(
            create_call_return_continuation(
                &stack,
                &stale_registers,
                &heap,
                valid_continuation_request(owner, frame, window),
            ),
            Err(ExecutionError::RegisterWindowMismatch)
        );

        let mut non_top_stack = stack.clone();
        let mut non_top_registers = registers.clone();
        non_top_stack
            .push_frame(
                &mut non_top_registers,
                FramePushRequest {
                    code_block: Some(owner),
                    callee: None,
                    callee_value: None,
                    lexical_scope: None,
                    shape: RegisterFrameShape {
                        num_parameters_including_this: 1,
                        num_vars: 1,
                        num_callee_locals: 0,
                        num_temporaries: 0,
                        special: Default::default(),
                    },
                    argument_count_including_this: 1,
                    argument_values: Vec::new(),
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
                None,
            )
            .unwrap();
        let top = non_top_stack.top_frame().unwrap().id;
        assert_eq!(
            create_call_return_continuation(
                &non_top_stack,
                &non_top_registers,
                &heap,
                valid_continuation_request(owner, frame, window),
            ),
            Err(ExecutionError::FrameMismatch {
                expected: frame,
                actual: Some(top),
            })
        );
    }

    #[test]
    fn js_call_pushes_callee_frame_with_caller_linkage_and_padded_arguments() {
        let function = function_code_block_with_parameters(
            vec![core_typed(
                0,
                CoreOpcode::Return,
                vec![Operand::Register(argument_including_this(2))],
            )],
            3,
        );
        let block = wide_program_code_block(vec![
            core_typed(
                0,
                CoreOpcode::LoadFunction,
                vec![
                    Operand::Register(local(0)),
                    Operand::UnsignedImmediate(0),
                    Operand::UnsignedImmediate(0),
                ],
            ),
            core_typed(
                1,
                CoreOpcode::LoadInt32,
                vec![Operand::Register(local(2)), Operand::SignedImmediate(7)],
            ),
            core_typed(
                2,
                CoreOpcode::Call,
                vec![
                    Operand::Register(local(1)),
                    Operand::Register(local(0)),
                    Operand::UnsignedImmediate(1),
                    Operand::Register(local(2)),
                ],
            ),
            core_typed(3, CoreOpcode::Return, vec![Operand::Register(local(1))]),
        ]);
        let owner = CodeBlockId(CellId(72));
        let mut stack = ExecutionContextStack::default();
        let mut registers = RegisterFile::default();
        let mut exceptions = ExceptionState::default();
        let mut heap = Heap::new();
        enter_program_frame(&mut stack, &mut registers, owner, &block, Vec::new());
        let caller = stack.top_frame().unwrap().id;
        let mut host = RecordingCallFrameHost::new(vec![function]);

        let completion = execute_code_block(
            InterpreterExecutionState {
                stack: &mut stack,
                registers: &mut registers,
                exceptions: &mut exceptions,
                heap: &mut heap,
            },
            owner,
            &block,
            &mut host,
            DispatchConfig::default(),
        );

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::undefined())
        );
        assert_eq!(host.snapshots.len(), 1);
        let snapshot = &host.snapshots[0];
        assert_eq!(snapshot.caller, Some(caller));
        assert_eq!(
            snapshot.arguments,
            vec![
                RuntimeValue::undefined(),
                RuntimeValue::from_i32(7),
                RuntimeValue::undefined(),
            ]
        );
        let continuation = snapshot.continuation.expect("callee continuation");
        assert_eq!(continuation.caller_frame, caller);
        assert_eq!(continuation.callee_frame, Some(snapshot.frame));
        assert_eq!(continuation.owner, owner);
        assert_eq!(
            continuation.call_bytecode_index,
            BytecodeIndex::from_offset(2)
        );
        assert_eq!(
            continuation.resume_bytecode_index,
            Some(BytecodeIndex::from_offset(3))
        );
        assert_eq!(continuation.destination, local(1));
        assert_eq!(continuation.argument_count_including_this, 2);
        assert_eq!(continuation.kind, CallReturnKind::Call);
    }

